import { createContext, useContext, useEffect, useState, useRef } from "react";
import { StreamChat } from "stream-chat";
import useAuthUser from "../hooks/useAuthUser";
import { useQuery } from "@tanstack/react-query";
import { getStreamToken } from "../lib/api";
import toast from "react-hot-toast";
import { useNavigate } from "react-router-dom";

const ChatContext = createContext(null);

export const useChatClient = () => useContext(ChatContext);

// === PERFORMANCE OPTIMIZATION: Global Audio Instance ===
// Initialized precisely once outside the component lifecycle to prevent redundant 
// browser API allocations and catastrophic DOM audio leaks.
const messageSound = new Audio("https://assets.mixkit.co/active_storage/sfx/2354/2354-preview.mp3");

// Safe audio trigger that handles rapid-fire sounds and browser policy rejections
const playNotificationSound = () => {
    messageSound.currentTime = 0;
    messageSound.play().catch((err) => console.warn("Audio autoplay blocked:", err));
};

export const ChatProvider = ({ children }) => {
    const [chatClient, setChatClient] = useState(null);
    const { authUser } = useAuthUser();
    const navigate = useNavigate();
    
    // Connection lock preventing duplicate network calls (Fixes StrictMode double-mounting)
    const connectionRef = useRef(null);

    // Fetch Stream Chat token (Cached for stability via React Query)
    const { data: tokenData, error: tokenError } = useQuery({
        queryKey: ["streamToken", authUser?._id],
        queryFn: getStreamToken,
        enabled: !!authUser?._id,
        staleTime: 5 * 60 * 1000,
        retry: 3,
    });

    // --- Error Handlers ---
    useEffect(() => {
        if (tokenError) {
            const status = tokenError.response?.status;
            const message = tokenError.response?.data?.message || tokenError.message;
            console.error("❌ Chat Token Failure:", { status, message });

            toast.error(
                `Messenger connection failed (${status || 'Network Error'}): ${message.substring(0, 30)}...`,
                { duration: 6000, id: "chat-token-error" } // Id prevents toast spam
            );
        }
    }, [tokenError]);

    // --- Core Connection Lifecycle ---
    useEffect(() => {
        if (!authUser?._id || !tokenData?.token || !tokenData?.apiKey) {
            if (authUser && !tokenData?.token) {
                console.warn("Chat connection delayed: Waiting for token from server...");
            }
            return;
        }

        let isMounted = true;
        let client = null;
        const currentUserId = String(authUser._id);
        const STREAM_API_KEY = tokenData.apiKey;

        const connectStream = async () => {
            try {
                // Prevent duplicate simultaneous connection sweeps in React
                if (connectionRef.current) await connectionRef.current;

                client = StreamChat.getInstance(STREAM_API_KEY);

                // Setup global debug helper safely for production environments
                window.logChatStatus = () => {
                    const status = {
                        currentUserId,
                        clientUserId: client?.userID,
                        keyPreview: `${STREAM_API_KEY.substring(0, 3)}...`,
                        isConnected: client?.userID === currentUserId
                    };
                    console.table(status);
                    return status;
                };

                // Safely lock connection routine mapping
                connectionRef.current = (async () => {
                    // Bypass WebRTC logic if socket is already bound properly
                    if (client.userID === currentUserId) {
                        return client; 
                    }

                    // Security: Disconnect if lingering socket from another user identity exists (Logout scenario)
                    if (client.userID && client.userID !== currentUserId) {
                        console.log("🔄 Disconnecting previous user socket:", client.userID);
                        await client.disconnectUser();
                    }

                    console.log("🔌 Connecting to Stream Chat as:", currentUserId);
                    await client.connectUser(
                        {
                            id: currentUserId,
                            name: authUser.fullName,
                            image: authUser.profilePic,
                        },
                        tokenData.token
                    );
                    
                    return client;
                })();

                await connectionRef.current;

                if (isMounted) {
                    console.log("✅ Chat connected successfully");
                    setChatClient(client);
                }

                // Global Message / Notification Handler
                // Wrapped directly in scope avoiding 'useCallback' dependencies to guarantee access to stable client references
                const handleNewMessage = (event) => {
                    // Ignore outbound sync sweeps from self
                    if (event.user?.id === currentUserId) return;

                    const isGroup = event.channel_type === "messaging" && event.channel_id.startsWith("group_");
                    const targetId = isGroup ? event.channel_id : event.user?.id;
                    
                    // Optimization: Read location dynamically off window object to bypass React render cycle dependencies.
                    // If we strictly checked react-router location hooks here, this provider would re-render the app on every page navigation.
                    const isOnChatPage = window.location.pathname.includes(`/chat/${targetId}`);
                    
                    if (!isOnChatPage && targetId) {
                        playNotificationSound();
                        
                        // Custom Notification Toast Architecture
                        toast((t) => (
                            <div 
                                className="flex items-center gap-3 cursor-pointer" 
                                onClick={() => {
                                    toast.dismiss(t.id);
                                    navigate(`/chat/${targetId}`);
                                }}
                            >
                                <div className="w-10 h-10 rounded-full overflow-hidden shrink-0 border border-white/10">
                                    <img 
                                        src={event.user?.image || "/avatar.png"} 
                                        alt={event.user?.name || "User"} 
                                        className="w-full h-full object-cover" 
                                    />
                                </div>
                                <div className="min-w-0">
                                    <p className="font-bold text-sm truncate text-white">
                                        {isGroup ? `${event.channel_id.replace('group_', '').replace(/_/g, ' ')}` : event.user?.name}
                                    </p>
                                    <p className="text-[10px] font-bold text-primary mb-0.5 truncate uppercase">
                                        {isGroup ? `${event.user?.name}:` : "New Message"}
                                    </p>
                                    <p className="text-xs text-white/80 truncate max-w-[150px]">
                                        {event.message?.text || "Sent an attachment"}
                                    </p>
                                </div>
                            </div>
                        ), { 
                            duration: 5000, 
                            position: "top-right", 
                            style: { borderRadius: '14px', background: '#1c1c1c', border: '1px solid #333', padding: '12px' },
                            id: `msg-${event.message?.id}` // Stability: Prevents identical messages from stacking toasts
                        });
                    }
                };

                // Bind exact listener instances
                client.on("message.new", handleNewMessage);
                client.on("notification.message_new", handleNewMessage);

                // Preserve reference tracking so cleanup phase isn't blinded by closure
                client._memoizedMessageHandler = handleNewMessage;

            } catch (error) {
                if (isMounted) {
                    const errorMsg = error.message || "Unknown connection error";
                    console.error("❌ Chat connection failed:", error);
                    toast.error(`Messenger error: ${errorMsg.substring(0, 60)}`, {
                        duration: 5000,
                        id: "chat-conn-error"
                    });
                }
            } finally {
                connectionRef.current = null;
            }
        };

        connectStream();

        // Memory Leak Prevention Module
        return () => {
            isMounted = false;
            
            if (client) {
                if (client._memoizedMessageHandler) {
                    // Detach explicit listener references avoiding floating background tasks processing dead webhook signals
                    client.off("message.new", client._memoizedMessageHandler);
                    client.off("notification.message_new", client._memoizedMessageHandler);
                    delete client._memoizedMessageHandler; // Purge
                }
                
                // Note: We deliberately DO NOT disconnect the user on simple component unmounts. 
                // Stream 'getInstance' maintains the active WebSocket efficiently locally across page navigations.
                // Complete disconnection logic is handled exclusively if the actual user identity changes (Line 104).
            }
            
            if (window.logChatStatus) {
                delete window.logChatStatus;
            }
        };
    // By monitoring strict primitive strings, we prevent unexpected recursive connections when entire auth objects mutate unrelated state.
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [tokenData?.token, tokenData?.apiKey, authUser?._id, navigate]); 

    return (
        <ChatContext.Provider value={chatClient}>
            {children}
        </ChatContext.Provider>
    );
};

import { useState, useRef, useEffect, useMemo, useCallback, memo } from "react";
import { createPost, getSongs } from "../lib/api";
import { ImageIcon, VideoIcon, X, Loader2, Play, BadgeCheck, Square } from "lucide-react";
import toast from "react-hot-toast";

// === ENVIRONMENT CONFIGURATION ===
const CLOUDINARY_CLOUD_NAME = import.meta.env.VITE_CLOUDINARY_CLOUD_NAME;
const CLOUDINARY_UPLOAD_PRESET = import.meta.env.VITE_CLOUDINARY_UPLOAD_PRESET;

// === GLOBAL AUDIO PREVIEW SAFEGUARD ===
// Ensures only one audio track can play at a time across the entire application
let currentAudioPreview = null;
const stopCurrentAudio = () => {
    if (currentAudioPreview) {
        currentAudioPreview.pause();
        currentAudioPreview.currentTime = 0;
        currentAudioPreview = null;
    }
};

// === CLOUDINARY DIRECT UPLOAD LOGIC ===
const uploadToCloudinary = (file, resourceType = "image", onProgress) => {
    return new Promise((resolve, reject) => {
        if (!CLOUDINARY_CLOUD_NAME || !CLOUDINARY_UPLOAD_PRESET) {
            reject(new Error("Cloudinary configuration missing in environment"));
            return;
        }

        const formData = new FormData();
        formData.append("file", file);
        formData.append("upload_preset", CLOUDINARY_UPLOAD_PRESET);

        const xhr = new XMLHttpRequest();
        xhr.open("POST", `https://api.cloudinary.com/v1_1/${CLOUDINARY_CLOUD_NAME}/${resourceType}/upload`);

        xhr.upload.onprogress = (e) => {
            if (e.lengthComputable && onProgress) {
                const percent = Math.round((e.loaded / e.total) * 100);
                onProgress(percent);
            }
        };

        xhr.onload = () => {
            try {
                const data = JSON.parse(xhr.responseText);
                if (xhr.status >= 200 && xhr.status < 300 && data.secure_url) {
                    resolve(data.secure_url);
                } else {
                    console.error("Cloudinary upload error response:", data);
                    reject(new Error(data.error?.message || "Upload failed"));
                }
            } catch (err) {
                reject(new Error("Failed to parse Cloudinary response"));
            }
        };

        xhr.onerror = () => reject(new Error("Network error during upload"));
        xhr.send(formData);
    });
};

// === HELPER COMPONENTS ===
// Shield inputs tightly to prevent keystroke lag
const PostInputs = memo(({ content, setContent, authUser }) => (
    <div className="flex items-start gap-3">
        <div className="avatar flex-shrink-0">
            <div className="w-10 h-10 rounded-full border border-base-content/10 overflow-hidden bg-base-300">
                <img
                    src={authUser?.profilePic || "/avatar.png"}
                    alt={authUser?.fullName}
                    className="object-cover w-full h-full"
                    loading="lazy"
                    decoding="async"
                />
                {(authUser?.isVerified || authUser?.role === "admin") && (
                    <div className="absolute -bottom-1 -right-1 size-4 bg-white rounded-full flex items-center justify-center p-[1px] shadow-sm ring-1 ring-base-content/5 overflow-hidden">
                        <BadgeCheck className="size-full text-white fill-[#1d9bf0]" strokeWidth={2} />
                    </div>
                )}
            </div>
        </div>
        <div className="flex-1 min-w-0 relative group">
            <textarea
                className="w-full bg-transparent resize-none text-[15px] focus:outline-none placeholder:opacity-50 min-h-[40px] leading-relaxed pt-2 pb-1"
                placeholder="Share your thoughts..."
                value={content}
                onChange={(e) => setContent(e.target.value)}
                rows={2}
            />
            {/* Animated focus indicator line */}
            <div className="absolute bottom-0 left-0 h-[1.5px] w-0 bg-primary group-focus-within:w-full transition-all duration-300 ease-out"></div>
        </div>
    </div>
));
PostInputs.displayName = "PostInputs";

// === MAIN UI COMPONENT ===
const CreatePost = memo(({ onPost, authUser }) => {
    // Media & State
    const [content, setContent] = useState("");
    const [mediaFile, setMediaFile] = useState(null);
    const [mediaType, setMediaType] = useState("");
    const [mediaPreview, setMediaPreview] = useState(null);
    
    // Audio Logic
    const [songName, setSongName] = useState("");
    const [audioUrl, setAudioUrl] = useState("");
    const [searchQuery, setSearchQuery] = useState("");
    const [songs, setSongs] = useState([]);
    const [currentPreviewPlaying, setCurrentPreviewPlaying] = useState(null);
    
    // Upload Pipeline Logic
    const [uploadStatus, setUploadStatus] = useState("idle"); // idle, uploading, posting
    const [uploadProgress, setUploadProgress] = useState(0);
    
    // Strict Hardware Pointers
    const imageInputRef = useRef(null);
    const videoInputRef = useRef(null);
    const previewTimeoutRef = useRef(null);

    // === MEMOIZED DERIVATIONS ===
    const filteredSongs = useMemo(() => {
        if (!searchQuery) return songs;
        const lowerQ = searchQuery.toLowerCase();
        return songs.filter(s =>
            s.title.toLowerCase().includes(lowerQ) ||
            s.artist.toLowerCase().includes(lowerQ)
        );
    }, [songs, searchQuery]);

    // === LIFECYCLE EFFECTS ===
    useEffect(() => {
        // Hydrate selected song from reels flow safely
        const preSelected = localStorage.getItem("preSelectedSong");
        if (preSelected) {
            try {
                const songData = JSON.parse(preSelected);
                setSongName(`${songData.title} - ${songData.artist}`);
                setAudioUrl(songData.audioUrl);
                setMediaType("video");
                localStorage.removeItem("preSelectedSong");
            } catch (e) {
                console.error("Error parsing preselected song", e);
            }
        }
    }, []);

    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const data = await getSongs();
                setSongs(data || []);
            } catch (err) {
                console.error("Error fetching songs:", err);
            }
        };
        fetchSongs();
    }, []);

    // Memory Leak Failsafe
    useEffect(() => {
        // Will cleanup any ObjectURLs lingering if the component unmounts mid-creation
        return () => {
            if (mediaPreview) URL.revokeObjectURL(mediaPreview);
            stopCurrentAudio();
            if (previewTimeoutRef.current) clearTimeout(previewTimeoutRef.current);
        };
    }, [mediaPreview]);


    // === STABLE HANDLERS ===
    const handleFileSelect = useCallback((e, type) => {
        const file = e.target.files?.[0];
        if (!file) return;

        // Failsafe: Replaces any existing file properly preventing 500MB overlapping URLs in RAM
        if (mediaPreview) URL.revokeObjectURL(mediaPreview);

        const maxSize = type === "video" ? 100 * 1024 * 1024 : 50 * 1024 * 1024;
        const maxLabel = type === "video" ? "100MB" : "50MB";
        
        if (file.size > maxSize) {
            toast.error(`File size must be under ${maxLabel}`);
            // Reset the invisible browser input so they can click it again safely
            e.target.value = "";
            return;
        }

        const previewUrl = URL.createObjectURL(file);
        setMediaFile(file);
        setMediaType(type);
        setMediaPreview(previewUrl);
        e.target.value = ""; // Clear file handle locking
    }, [mediaPreview]);

    const removeMedia = useCallback(() => {
        if (mediaPreview) URL.revokeObjectURL(mediaPreview);
        setMediaFile(null);
        setMediaType("");
        setMediaPreview(null);
        setSongName("");
        setAudioUrl("");
        setUploadProgress(0);
        
        if (imageInputRef.current) imageInputRef.current.value = "";
        if (videoInputRef.current) videoInputRef.current.value = "";
    }, [mediaPreview]);

    const handleAudioPreview = useCallback((songUrl, songId) => {
        stopCurrentAudio();
        
        if (currentPreviewPlaying === songId) {
            // Toggle off behaviour
            setCurrentPreviewPlaying(null);
            if (previewTimeoutRef.current) clearTimeout(previewTimeoutRef.current);
            return;
        }

        const audio = new Audio(songUrl);
        
        audio.play().then(() => {
            currentAudioPreview = audio;
            setCurrentPreviewPlaying(songId);
            
            // Auto stop logic
            if (previewTimeoutRef.current) clearTimeout(previewTimeoutRef.current);
            previewTimeoutRef.current = setTimeout(() => {
                stopCurrentAudio();
                setCurrentPreviewPlaying(null);
            }, 6000); // Strict 6 second preview limit to save data
            
        }).catch(err => {
            toast.error("Wait for audio to load.");
        });
    }, [currentPreviewPlaying]);

    const handlePost = useCallback(async () => {
        const trimmedContent = content.trim();

        if (!trimmedContent && !mediaFile) {
            toast.error("Write something or add media");
            return;
        }
        if (uploadStatus !== "idle") {
            return; // Throttle double clicks
        }

        setUploadStatus("uploading");
        setUploadProgress(0);

        try {
            let mediaUrlResp = "";
            let mediaBase64 = null;

            if (mediaFile) {
                try {
                    toast.loading(`Uploading ${mediaType}...`, { id: "upload-status" });
                    
                    mediaUrlResp = await uploadToCloudinary(mediaFile, mediaType, (progress) => {
                        setUploadProgress(progress);
                    });
                    
                } catch (uploadError) {
                    console.warn("Direct upload failed, attempting backend fallback...", uploadError);

                    if (mediaFile.size < 10 * 1024 * 1024) {
                        toast.loading("Uploading via backend...", { id: "upload-status" });
                        
                        const reader = new FileReader();
                        mediaBase64 = await new Promise((resolve, reject) => {
                            reader.onloadend = () => resolve(reader.result);
                            reader.onerror = () => reject(new Error("File conversion failed"));
                            reader.readAsDataURL(mediaFile);
                        });
                    } else {
                        throw new Error(`File too large for fallback system (${Math.round(mediaFile.size/1024/1024)}MB). Please connect to a stable network.`);
                    }
                }
            }

            setUploadStatus("posting");
            toast.loading("Publishing...", { id: "upload-status" });

            const postData = {
                content: trimmedContent,
                mediaUrl: mediaUrlResp,
                media: mediaBase64,
                mediaType,
                songName: songName.trim(),
                audioUrl: audioUrl,
            };

            const saved = await createPost(postData);
            onPost(saved);
            
            // Safe Structural Tear Down
            setContent("");
            removeMedia();
            toast.success("Post published!", { id: "upload-status" });

        } catch (error) {
            const errorMsg = error.response?.data?.message || error.message || "Failed to create post";
            toast.error(errorMsg, { id: "upload-status" });
        } finally {
            setUploadStatus("idle");
            setUploadProgress(0);
        }
    }, [content, mediaFile, uploadStatus, mediaType, songName, audioUrl, onPost, removeMedia]);


    // === RENDER ===
    const isWorking = uploadStatus !== "idle";

    return (
        <div className="flex flex-col gap-3 p-4 bg-base-100 rounded-[8px] border border-base-content/10 shadow-[0_0_0_1px_rgba(255,255,255,0.05)]">
            
            <PostInputs content={content} setContent={setContent} authUser={authUser} />

            {/* Media Preview Container */}
            {mediaPreview && (
                <div className="relative mt-2 rounded-2xl overflow-hidden bg-base-300 border border-base-content/10 mx-auto w-full max-w-2xl animate-in fade-in slide-in-from-bottom-2 duration-300">
                    <button
                        onClick={removeMedia}
                        disabled={isWorking}
                        aria-label="Remove media"
                        className="absolute top-3 right-3 btn btn-circle btn-sm bg-black/60 hover:bg-black/90 text-white border-none z-10 active:scale-90 transition-all backdrop-blur-md shadow-lg disabled:opacity-50"
                    >
                        <X className="size-4" />
                    </button>
                    {mediaType === "image" ? (
                        <img
                            src={mediaPreview}
                            alt="Upload preview"
                            className="w-full max-h-[400px] object-cover"
                            loading="eager"
                        />
                    ) : (
                        <video
                            src={mediaPreview}
                            controls
                            playsInline
                            className="w-full max-h-[400px] bg-black"
                            preload="auto"
                        />
                    )}
                </div>
            )}

            {/* Smart Progress Pipeline UI */}
            {isWorking && uploadProgress > 0 && (
                <div className="mt-2 w-full animate-in fade-in duration-300">
                    <div className="flex items-center justify-between text-[10px] font-bold uppercase tracking-widest mb-1.5 px-0.5">
                        <span className="opacity-50">{uploadStatus === "uploading" ? "Syncing to edge network" : "Publishing to feeds"}</span>
                        <span className="text-primary">{uploadProgress}%</span>
                    </div>
                    <div className="h-1.5 w-full bg-base-300 rounded-full overflow-hidden">
                        <div
                            className="h-full bg-primary transition-all duration-300 ease-out relative"
                            style={{ width: `${uploadProgress}%` }}
                        >
                            <div className="absolute inset-0 bg-white/20 w-full animate-[shimmer_1s_infinite]"></div>
                        </div>
                    </div>
                </div>
            )}

            {/* Song Audio Extractor Module (Videos Only) */}
            {mediaType === "video" && (
                <div className="mt-4 p-4 rounded-2xl bg-base-200/50 border border-base-content/5 space-y-4 animate-in fade-in duration-300">
                    <div className="flex flex-col sm:flex-row gap-3">
                        <input
                            type="text"
                            placeholder="Search trending audio..."
                            className="input-premium w-full flex-1 rounded-xl text-sm"
                            onChange={(e) => setSearchQuery(e.target.value)}
                            value={searchQuery}
                            disabled={isWorking}
                        />
                        {songName && (
                            <div className="flex-1 px-4 py-2.5 bg-primary/10 rounded-xl border border-primary/20 flex items-center shadow-inner">
                                <span className="text-xs font-black text-primary uppercase tracking-wider truncate w-full">
                                    {songName}
                                </span>
                            </div>
                        )}
                    </div>

                    <div className="flex flex-wrap gap-2 max-h-40 overflow-y-auto p-1 custom-scrollbar">
                        {filteredSongs.length > 0 ? filteredSongs.map((song) => {
                            const label = `${song.title} - ${song.artist}`;
                            const isSelected = songName === label;
                            const isPlaying = currentPreviewPlaying === song._id;

                            return (
                                <div key={song._id} className={`flex items-center gap-1 pl-3 pr-1 py-1 rounded-full border transition-all ${isSelected ? 'bg-primary/10 border-primary text-primary shadow-sm' : 'bg-base-100 border-base-content/10 hover:border-primary/50 text-base-content/70'}`}>
                                    <button
                                        onClick={() => {
                                            setSongName(label);
                                            setAudioUrl(song.audioUrl);
                                        }}
                                        disabled={isWorking}
                                        className="text-xs font-semibold cursor-pointer truncate max-w-[120px] sm:max-w-xs transition-colors"
                                    >
                                        {label}
                                    </button>
                                    {song.audioUrl && (
                                        <button
                                            className={`btn btn-ghost btn-xs btn-circle ${isSelected ? 'text-primary' : 'text-base-content/40 hover:text-primary'} ${isPlaying ? 'bg-primary/20 animate-pulse' : ''}`}
                                            disabled={isWorking}
                                            onClick={(e) => {
                                                e.preventDefault();
                                                handleAudioPreview(song.audioUrl, song._id);
                                            }}
                                            aria-label={isPlaying ? "Stop audio preview" : "Play audio preview"}
                                        >
                                            {isPlaying ? <Square className="size-3.5 fill-current" /> : <Play className="size-3.5 fill-current" />}
                                        </button>
                                    )}
                                </div>
                            );
                        }) : (
                            <span className="text-[10px] font-semibold uppercase tracking-widest opacity-40 px-2 py-1">{searchQuery ? "No songs found" : "Loading library..."}</span>
                        )}
                        {!searchQuery && songs.length === 0 && (
                            <button
                                onClick={() => {
                                    setSongName("Original Audio");
                                    setAudioUrl("");
                                }}
                                disabled={isWorking}
                                className={`text-xs font-semibold px-4 py-1.5 rounded-full border transition-all cursor-pointer ${songName === "Original Audio" ? 'bg-primary/10 border-primary text-primary shadow-sm' : 'bg-base-100 border-base-content/10 hover:border-primary/50 text-base-content/70'}`}
                            >
                                Original Audio
                            </button>
                        )}
                    </div>
                </div>
            )}

            {/* Action Triggers Configuration */}
            <div className="flex items-center justify-between mt-2 pt-4 border-t border-base-content/5">
                <div className="flex items-center gap-2">
                    <label className={`group flex items-center justify-center size-10 rounded-full transition-colors ${isWorking ? 'opacity-50 cursor-not-allowed' : 'hover:bg-base-200 cursor-pointer'}`}>
                        <ImageIcon className="size-5 text-base-content/50 group-hover:text-success transition-colors" />
                        <input
                            ref={imageInputRef}
                            type="file"
                            accept="image/*"
                            className="hidden"
                            disabled={isWorking}
                            onChange={(e) => handleFileSelect(e, "image")}
                        />
                    </label>

                    <label className={`group flex items-center justify-center size-10 rounded-full transition-colors ${isWorking ? 'opacity-50 cursor-not-allowed' : 'hover:bg-base-200 cursor-pointer'}`}>
                        <VideoIcon className="size-5 text-base-content/50 group-hover:text-info transition-colors" />
                        <input
                            ref={videoInputRef}
                            type="file"
                            accept="video/*"
                            className="hidden"
                            disabled={isWorking}
                            onChange={(e) => handleFileSelect(e, "video")}
                        />
                    </label>
                </div>

                <button
                    className="btn btn-primary rounded-xl px-8 shadow-[0_4px_14px_0_oklch(var(--p)/0.3)] hover:shadow-[0_6px_20px_oklch(var(--p)/0.23)] hover:-translate-y-0.5 active:scale-95 transition-all duration-200 text-sm font-bold h-10 min-h-10"
                    onClick={handlePost}
                    disabled={isWorking || (!content.trim() && !mediaFile)}
                >
                    {isWorking ? (
                        <>
                            <Loader2 className="size-4 animate-spin" />
                            <span className="opacity-90">{uploadProgress > 0 && uploadProgress < 100 ? `${uploadProgress}%` : "Posting"}</span>
                        </>
                    ) : (
                        "Publish"
                    )}
                </button>
            </div>
        </div>
    );
});
CreatePost.displayName = "CreatePost";

export default CreatePost;

import React from 'react';
import { motion } from 'framer-motion';
import { DollarSign, Users, TrendingUp, Gem, Activity, CreditCard, Award, ArrowUpRight } from 'lucide-react';
import { useQuery } from '@tanstack/react-query';
import { axiosInstance } from '../lib/axios';

/**
 * Creator Dashboard — The monetization command center for Zyro Creators.
 * Features glassmorphism, real-time metrics, and Elite Fan tracking.
 */

const StatCard = ({ icon: Icon, label, value, trend, colorClass, isLoading }) => (
  <motion.div 
    whileHover={{ y: -5 }}
    className={`bg-white/5 backdrop-blur-xl border border-white/10 p-6 rounded-[2.5rem] relative overflow-hidden group ${isLoading ? 'animate-pulse' : ''}`}
  >
    <div className={`absolute top-0 right-0 size-24 blur-[60px] opacity-20 transition-all group-hover:opacity-40 ${colorClass}`} />
    <div className="flex justify-between items-start mb-6">
      <div className={`p-4 rounded-2xl ${colorClass}/10 text-white`}>
        <Icon className="size-6" />
      </div>
      {!isLoading && (
        <div className={`flex items-center gap-1 text-xs font-black ${trend > 0 ? 'text-green-400' : 'text-red-400'}`}>
          <ArrowUpRight className={`size-3 ${trend < 0 ? 'rotate-90' : ''}`} />
          {Math.abs(trend)}%
        </div>
      )}
    </div>
    <div>
      <p className="text-white/30 text-[10px] font-black uppercase tracking-[0.2em]">{label}</p>
      <h3 className="text-3xl font-black text-white mt-1 tracking-tighter">
        {isLoading ? "---" : value}
      </h3>
    </div>
  </motion.div>
);

const CreatorDashboard = () => {
  // Fetch Stats
  const { data: stats, isLoading: statsLoading } = useQuery({
    queryKey: ['creatorStats'],
    queryFn: async () => {
      const res = await axiosInstance.get('/creator/stats');
      return res.data;
    }
  });

  // Fetch Bonds
  const { data: bonds, isLoading: bondsLoading } = useQuery({
    queryKey: ['creatorBonds'],
    queryFn: async () => {
      const res = await axiosInstance.get('/creator/bonds');
      return res.data;
    }
  });

  // Fetch Elite Fans
  const { data: eliteFans, isLoading: fansLoading } = useQuery({
    queryKey: ['creatorEliteFans'],
    queryFn: async () => {
      const res = await axiosInstance.get('/creator/elite-fans');
      return res.data;
    }
  });

  return (
    <div className="min-h-screen bg-[#050505] p-6 lg:p-12 text-white font-outfit overflow-x-hidden">
      <div className="max-w-7xl mx-auto space-y-12">
        
        {/* Header Section */}
        <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div className="space-y-1">
            <motion.div 
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              className="flex items-center gap-3 text-indigo-500 font-black text-xs uppercase tracking-[0.3em]"
            >
              <div className="size-2 bg-indigo-500 animate-pulse rounded-full" /> LIVE REVENUE ENGINE
            </motion.div>
            <h1 className="text-5xl font-black tracking-tighter bg-gradient-to-r from-white to-white/40 bg-clip-text text-transparent">Creator Suite</h1>
          </div>
          
          <div className="flex items-center gap-4">
            <button className="px-6 py-4 bg-white/5 border border-white/10 rounded-2xl font-bold hover:bg-white/10 transition-all flex items-center gap-2">
              <CreditCard className="size-4" /> Withdraw
            </button>
            <button className="px-8 py-4 bg-indigo-600 rounded-2xl font-black shadow-lg shadow-indigo-500/20 hover:scale-105 transition-all flex items-center gap-2">
              New Digital Bond <Gem className="size-4" />
            </button>
          </div>
        </header>

        {/* Global Performance Section */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <StatCard icon={DollarSign} label="Wallet Balance" value={stats?.walletBalance || "$0.00"} trend={stats?.trends?.revenue || 0} colorClass="bg-emerald-500" isLoading={statsLoading} />
          <StatCard icon={Users} label="Premium Bonds" value={stats?.totalBonds || "0"} trend={stats?.trends?.bonds || 0} colorClass="bg-indigo-500" isLoading={statsLoading} />
          <StatCard icon={Award} label="Top 1% Fans" value={stats?.eliteFansCount || "0"} trend={stats?.trends?.fans || 0} colorClass="bg-purple-500" isLoading={statsLoading} />
          <StatCard icon={Activity} label="Vibe Velocity" value={stats?.vibeVelocity || "Stable"} trend={0} colorClass="bg-orange-500" isLoading={statsLoading} />
        </div>

        {/* Main Content: Bonds & Elite Fans */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          
          {/* Active Bonds Table */}
          <div className="lg:col-span-8 bg-white/5 border border-white/5 rounded-[3rem] p-8 relative overflow-hidden">
             <div className="relative z-10">
                <div className="flex justify-between items-center mb-10">
                  <h2 className="text-2xl font-black tracking-tighter">Active Digital Bonds</h2>
                  <div className="flex gap-2">
                    <div className="size-2 rounded-full bg-indigo-500" />
                    <div className="size-2 rounded-full bg-white/10" />
                  </div>
                </div>

                <div className="space-y-4">
                  {bondsLoading ? (
                    <div className="p-10 text-center opacity-20">Scanning Assets...</div>
                  ) : bonds?.length === 0 ? (
                    <div className="p-10 text-center border-2 border-dashed border-white/5 rounded-[2rem] text-white/20 font-bold uppercase tracking-widest">
                       No Digital Bonds Minted Yet
                    </div>
                  ) : bonds?.map((item, idx) => (
                    <motion.div 
                      key={item._id}
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: idx * 0.1 }}
                      className="flex items-center justify-between p-6 bg-white/5 rounded-[2rem] border border-white/5 hover:border-white/20 transition-all group"
                    >
                      <div className="flex items-center gap-5">
                        <div className="size-14 bg-gradient-to-tr from-indigo-500 to-violet-600 rounded-2xl flex items-center justify-center font-black text-xl shadow-lg ring-4 ring-indigo-500/10">
                          {item.name[0]}
                        </div>
                        <div>
                          <h4 className="font-bold text-lg group-hover:text-indigo-400 transition-colors">{item.name}</h4>
                          <span className="text-[10px] font-black uppercase tracking-widest text-white/30">
                            {item.isSold ? "Owner: Syncing..." : "Awaiting Collector"}
                          </span>
                        </div>
                      </div>
                      <div className="flex items-center gap-12">
                         <div className="hidden md:block text-right">
                           <p className="text-[10px] font-black text-white/30 uppercase mb-1">Unit Price</p>
                           <p className="font-bold">{item.price} Gems</p>
                         </div>
                         <div className="text-right">
                           <p className="text-[10px] font-black text-indigo-400 uppercase mb-1">Status</p>
                           <p className="font-black text-xl uppercase tracking-tighter">{item.rarity}</p>
                         </div>
                      </div>
                    </motion.div>
                  ))}
                </div>
             </div>
          </div>

          {/* Elite Fan Leaderboard */}
          <div className="lg:col-span-4 space-y-8">
             <div className="bg-indigo-600 rounded-[3rem] p-8 shadow-2xl shadow-indigo-500/20">
                <h3 className="text-xl font-black mb-8 italic">The Elite Tier</h3>
                <div className="space-y-8">
                   {fansLoading ? (
                     <div className="opacity-50">Syncing Fan Neural States...</div>
                   ) : eliteFans?.length === 0 ? (
                     <div className="text-sm font-bold opacity-40 italic">Deep engagement data pending...</div>
                   ) : eliteFans?.map((fan, i) => (
                     <div key={fan._id} className="flex items-center gap-4">
                        <div className="size-10 rounded-full border-2 border-white/20 flex items-center justify-center font-bold text-xs">{i+1}</div>
                        <div className="flex-1">
                           <div className="flex justify-between items-center mb-2">
                             <span className="font-bold text-sm tracking-tight">{fan.fanId?.name || "Fan"}</span>
                             <span className="text-[10px] font-black">{fan.bondScore} pts</span>
                           </div>
                           <div className="h-1.5 w-full bg-black/10 rounded-full overflow-hidden">
                              <motion.div 
                                initial={{ width: 0 }}
                                animate={{ width: `${Math.min(100, fan.bondScore / 100)}%` }}
                                className="h-full bg-white rounded-full" 
                              />
                           </div>
                        </div>
                     </div>
                   ))}
                </div>
                {eliteFans?.length > 0 && (
                  <button className="w-full mt-10 py-4 bg-white text-indigo-600 rounded-2xl font-black hover:bg-gray-100 transition-all shadow-xl">
                    AIRDROP REWARDS
                  </button>
                )}
             </div>

             <div className="bg-white/5 border border-white/10 rounded-[3rem] p-8 text-center">
                <Activity className="size-8 text-white/20 mx-auto mb-4" />
