import { memo, useState, useCallback } from "react";
import { Link } from "react-router-dom";
import { MessageCircle, BadgeCheck } from "lucide-react";
import ProfilePhotoViewer from "./ProfilePhotoViewer";
import { LANGUAGE_TO_FLAG } from "../constants";

// === PERFORMANCE OPTIMIZATION: Pure Helper Function ===
// Extracted rendering function outside the component tree to prevent 
// re-evaluating and allocating function memory on every single card render.
export const getLanguageFlag = (language) => {
  if (!language) return null;

  const langLower = language.toLowerCase();
  const countryCode = LANGUAGE_TO_FLAG[langLower];

  if (countryCode) {
    return (
      <img
        src={`https://flagcdn.com/24x18/${countryCode}.png`}
        alt={`${langLower} flag`}
        className="h-3 mr-0.5 inline-block"
        loading="lazy" // Network optimization: prevent 100+ flags loading un-scrolled
      />
    );
  }
  return null;
}

// === COMPONENT: FriendCard ===
// Wrapped in React.memo to completely halt re-renders if the main parent array 
// or feed alters state, guaranteeing smooth 60fps timeline scrolling.
const FriendCard = memo(({ friend }) => {
  const [viewingDP, setViewingDP] = useState(null);

  // Stable callbacks using useCallback prevent the ProfilePhotoViewer and event listeners
  // from silently tearing down and remounting.
  const handleViewDP = useCallback(() => {
    setViewingDP({ 
      url: friend.profilePic || "/avatar.png", 
      name: friend.fullName 
    });
  }, [friend.profilePic, friend.fullName]);

  const handleCloseDP = useCallback(() => {
    setViewingDP(null);
  }, []);

  const profileImg = friend.profilePic || "/avatar.png";
  const isVerified = friend.isVerified || friend.role === "admin";

  return (
    <div className="card bg-base-200/80 border border-base-300/50 hover:border-primary/20 card-hover rounded-2xl overflow-hidden group/friendcard transition-all duration-300">
      <div className="card-body p-4">
        {/* USER INFO */}
        <div className="flex items-center gap-3 mb-3">
          <div className="relative">
            <div
              className="avatar w-12 h-12 rounded-full overflow-hidden ring-2 ring-base-300 group-hover/friendcard:ring-primary/30 transition-all cursor-pointer active:scale-95"
              onClick={handleViewDP}
              role="button"
              aria-label={`View ${friend.fullName}'s profile photo`}
            >
              <img
                src={profileImg}
                alt={friend.fullName}
                className="w-full h-full object-cover"
                loading="lazy"
                decoding="async" // Offloads image decoding from the main UI thread
              />
            </div>
            <span className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-success rounded-full border-2 border-base-200" />
          </div>
          <Link to={`/user/${friend._id}`} className="flex-1 min-w-0 hover:text-primary transition-colors">
            <h3 className="font-semibold text-sm truncate flex items-center gap-1">
              {friend.fullName}
              {isVerified && (
                <BadgeCheck className="size-3.5 text-white fill-[#1d9bf0]" strokeWidth={1.5} />
              )}
            </h3>
            <p className="text-[11px] text-base-content/40 font-medium truncate">
              @{friend.username || "user"}
            </p>
          </Link>
        </div>

        <div className="flex flex-wrap gap-1.5 mb-3">
          <span className="badge badge-secondary badge-sm gap-1 font-medium">
            {getLanguageFlag(friend.nativeLanguage)}
            {friend.nativeLanguage}
          </span>
          <span className="badge badge-outline badge-sm gap-1 font-medium">
            {getLanguageFlag(friend.learningLanguage)}
            {friend.learningLanguage}
          </span>
        </div>

        <Link
          to={`/chat/${friend._id}`}
          className="btn btn-primary btn-sm w-full rounded-xl gap-2 shadow-sm shadow-primary/20 hover:shadow-primary/40 hover:scale-[1.02] transition-all duration-300"
        >
          <MessageCircle className="size-4" />
          Message
        </Link>
      </div>

      {viewingDP && (
        <ProfilePhotoViewer
          imageUrl={viewingDP.url}
          fullName={viewingDP.name}
          isVerified={isVerified}
          onClose={handleCloseDP}
        />
      )}
    </div>
  );
});

FriendCard.displayName = "FriendCard";
export default FriendCard;

import { motion, AnimatePresence } from "framer-motion";
import { Gem, Flame, Sparkles, TrendingUp } from "lucide-react";
import { useState, useEffect, useCallback, useMemo, memo } from "react";
import { claimDailyReward } from "../lib/api";
import { useQueryClient } from "@tanstack/react-query";
import toast from "react-hot-toast";
import useAuthUser from "../hooks/useAuthUser";

// === ANIMATION CONFIGURATION ===
// Extracted out of render to prevent re-calculating random arrays continuously
const generateConfettiPaths = () => {
    return Array.from({ length: 15 }).map(() => ({
        scale: [0, 1, 0.5],
        x: (Math.random() - 0.5) * 400,
        y: (Math.random() - 0.5) * 600,
        size: Math.floor(Math.random() * 4) + 4
    }));
};

// === SUBCOMPONENT: Confetti Blast ===
// Shielded component that doesn't re-render unless explicitly triggered
const ConfettiBlast = memo(({ show, paths }) => {
    if (!show) return null;
    
    return (
        <div className="absolute inset-0 pointer-events-none overflow-hidden">
            {paths.map((config, i) => (
                <motion.div
                    key={`gem-${i}`}
                    initial={{ scale: 0, x: 0, y: 0, opacity: 1 }}
                    animate={{
                        scale: config.scale,
                        x: config.x,
                        y: config.y,
                        opacity: [1, 1, 0]
                    }}
                    transition={{ duration: 1.2, ease: "easeOut" }}
                    className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2"
                >
                    <Gem className={`size-${config.size} text-amber-400 fill-amber-300 shadow-lg`} />
                </motion.div>
            ))}
        </div>
    );
});
ConfettiBlast.displayName = "ConfettiBlast";

// === MAIN UI COMPONENT ===
const GemDrop = memo(() => {
    const { authUser } = useAuthUser();
    const queryClient = useQueryClient();
    const [isVisible, setIsVisible] = useState(false);
    const [isClaiming, setIsClaiming] = useState(false);
    const [showBlast, setShowBlast] = useState(false);

    // === REWARD ELIGIBILITY LOGIC ===
    // Memoized date comparison prevents object recreation on every scroll tick
    const isEligibleToday = useMemo(() => {
        if (!authUser) return false;
        
        const todayStr = new Date().toISOString().split('T')[0];
        let lastClaimStr = null;
        
        if (authUser.lastRewardClaimDate) {
            lastClaimStr = new Date(authUser.lastRewardClaimDate).toISOString().split('T')[0];
        }
        
        return lastClaimStr !== todayStr;
    }, [authUser?.lastRewardClaimDate, authUser?._id]);

    useEffect(() => {
        let timer;
        
        if (isEligibleToday) {
            // Only show if not on a "distraction-free" page like chat or reels
            const path = window.location.pathname;
            if (!path.includes("/chat") && !path.includes("/call") && !path.includes("/reels")) {
                // Delay briefly for organic impact, store strict reference for cleanup
                timer = setTimeout(() => setIsVisible(true), 1500);
            }
        }

        return () => {
            if (timer) clearTimeout(timer);
        };
    }, [isEligibleToday]);

    // Generate static confetti map exactly once
    const confettiPaths = useMemo(() => generateConfettiPaths(), []);

    // === COMPONENT DERIVATIONS ===
    const { streak = 0 } = authUser || {};
    const nextMilestone = useMemo(() => Math.ceil((streak + 1) / 7) * 7, [streak]);
    const progress = useMemo(() => (streak % 7) / 7 * 100, [streak]);

    // === HANDLERS ===
    const handleClose = useCallback(() => setIsVisible(false), []);

    const handleClaim = useCallback(async () => {
        if (isClaiming) return;
        setIsClaiming(true);

        try {
            // Android bridge safety wrapper
            if (typeof window !== "undefined" && window.AndroidBridge) {
               try { window.AndroidBridge.vibrate(100); } catch (e) { /* ignore */ }
            }
            
            const res = await claimDailyReward();
            setShowBlast(true);

            toast.success(res.message, {
                icon: '💎',
                style: { borderRadius: '20px', background: '#1c1c1c', color: '#fff' }
            });

            // Targeted invalidation prevents mass UI unmounting
            queryClient.invalidateQueries({ queryKey: ["authUser"], exact: true });

            // Keep visible for blast animation to finish
            setTimeout(() => {
                setIsVisible(false);
                setIsClaiming(false);
                setShowBlast(false);
            }, 1200);

        } catch (err) {
            toast.error(err.response?.data?.message || "Reward no longer available");
            setIsVisible(false);
            setIsClaiming(false);
        }
    }, [isClaiming, queryClient]);

    // Safe early exit (after hooks rule applied)
    if (!authUser) return null;

    return (
        <AnimatePresence>
            {isVisible && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="fixed inset-0 z-[1000] flex items-center justify-center p-6 bg-black/80 backdrop-blur-md lg:hidden"
                >
                    {/* Abstracted Confetti Blast Layer */}
                    <ConfettiBlast show={showBlast} paths={confettiPaths} />

                    <motion.div
                        initial={{ scale: 0.5, y: 100, rotate: -10 }}
                        animate={{ scale: 1, y: 0, rotate: 0 }}
                        exit={{ scale: 1.2, opacity: 0, filter: "blur(10px)" }}
                        transition={{ type: "spring", damping: 15 }}
                        className="w-full max-w-sm relative"
                    >
                        {/* Glossy Card */}
                        <div className="relative overflow-hidden rounded-[32px] bg-gradient-to-br from-amber-400 via-yellow-500 to-amber-700 p-1 shadow-[0_20px_50px_rgba(245,158,11,0.5)] border border-white/30">

                            {/* Background Glow */}
                            <div className="absolute -top-24 -right-24 size-48 bg-white/20 blur-3xl rounded-full" />
                            <div className="absolute -bottom-24 -left-24 size-48 bg-black/20 blur-3xl rounded-full" />

                            <div className="relative bg-black/10 backdrop-blur-sm rounded-[30px] p-6 sm:p-8 flex flex-col items-center text-center gap-6">

                                {/* Visual Header */}
                                <div className="relative">
                                    <motion.div
                                        animate={{
                                            scale: [1, 1.1, 1],
                                            rotate: [0, 5, -5, 0]
                                        }}
                                        transition={{ duration: 4, repeat: Infinity }}
                                        className="size-24 rounded-3xl bg-white/10 backdrop-blur-md flex items-center justify-center border border-white/20 shadow-2xl"
                                    >
                                        <Gem className="size-14 text-white drop-shadow-[0_0_15px_rgba(255,255,255,0.8)]" />
                                    </motion.div>
                                    <motion.div
