                <Link to={`/user/${post.userId}`} className="font-semibold hover:opacity-50 tracking-tight">
                  {post.fullName || "user"}
                </Link>
              )}
              {(post.isVerified || post.role === "admin") && (
                  <div className="flex items-center justify-center shrink-0" title="Verified Professional">
                     <BadgeCheck className="size-3.5 text-white fill-[#1d9bf0]" strokeWidth={1.5} />
                  </div>
              )}
            </div>
            {post.caption && (
              <span className="text-[14px] mr-1">
                {emotionEmoji[post.caption.toLowerCase()]} {post.caption}
              </span>
            )}
            <span className="text-base-content/90 break-words whitespace-pre-wrap flex-inline pl-1">
              {post.content}
            </span>
        </div>
    );
});
PostCaption.displayName = "PostCaption";

// === SUBCOMPONENT: Comment Input Form ===
// Encapsulates keystroke state ensuring typing 30WPM doesn't stall the feed GPU loop
const PostCommentInput = memo(({ onComment, isCommenting }) => {
    const [text, setText] = useState("");

    const handleSubmit = useCallback(async () => {
        if (!text.trim() || isCommenting) return;
        
        const success = await onComment(text.trim());
        if (success) {
            setText("");
        }
    }, [text, isCommenting, onComment]);

    return (
        <div className="px-0 flex items-center justify-between border-b border-transparent focus-within:border-base-content/20 py-1 transition-colors">
            <input
                type="text"
                placeholder="Add a comment..."
                className="bg-transparent border-none outline-none text-[14px] w-full placeholder:text-base-content/50 h-8"
                value={text}
                onChange={(e) => setText(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
            />
            <AnimatePresence>
                {text.trim() && (
                  <motion.button 
                    initial={{ opacity: 0, scale: 0.8 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.8 }}
                    onClick={handleSubmit}
                    disabled={isCommenting}
                    className="text-blue-500 font-semibold text-[14px] hover:text-blue-600 pl-2 transition-colors disabled:opacity-50"
                  >
                    Post
                  </motion.button>
                )}
            </AnimatePresence>
        </div>
    );
});
PostCommentInput.displayName = "PostCommentInput";

// === MAIN CARD COMPONENT ===
const PostCard = memo(({ post, setPosts, setLikedByPostId, setViewingDP }) => {
  const { authUser } = useAuthUser();
  const [showComments, setShowComments] = useState(false);
  const [isLiking, setIsLiking] = useState(false);
  const [isCommenting, setIsCommenting] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [showHeartOverlay, setShowHeartOverlay] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  
  const lastTap = useRef(0);
  
  const isLiked = post?.likes?.includes(authUser?._id) || false;
  const likeCount = post?.likes?.length || 0;
  const commentCount = post?.comments?.length || 0;

  // === STABLE HANDLERS ===
  const handleDelete = useCallback(async () => {
    if (!window.confirm("Are you sure you want to delete this post?")) return;
    setIsDeleting(true);
    try {
      await deletePost(post._id);
      setPosts((prev) => prev.filter((p) => p && p._id !== post._id));
      toast.success("Post deleted");
    } catch {
      toast.error("Failed to delete post");
    } finally {
      setIsDeleting(false);
    }
  }, [post._id, setPosts]);

  const handleLike = useCallback(async () => {
    if (isLiking) return;
    
    // Aggressive Optimistic UI Strategy
    const wasLiked = isLiked;
    setIsLiking(true);

    const newLikes = wasLiked 
        ? post.likes.filter(id => id !== authUser?._id)
        : [...(post.likes || []), authUser?._id];

    // Instantly inject into parent cache
    setPosts(prev => prev.map(p => p?._id === post._id ? { ...p, likes: newLikes } : p));

    try {
      const data = await likePost(post._id);
      // Reconcile with verified backend state
      setPosts(prev => prev.map(p => p?._id === post._id ? { ...p, likes: data.likes } : p));
    } catch {
      // Revert forcefully on error
      setPosts(prev => prev.map(p => p?._id === post._id ? { ...p, likes: post.likes } : p));
      toast.error("Failed to like post");
    } finally {
      setIsLiking(false);
    }
  }, [isLiking, isLiked, post._id, post.likes, authUser?._id, setPosts]);

  const handleDoubleTap = useCallback((e) => {
    const now = Date.now();
    const DOUBLE_TAP_DELAY = 300;
    if (now - lastTap.current < DOUBLE_TAP_DELAY) {
      if (!isLiked) handleLike();
      
      setShowHeartOverlay(true);
      setTimeout(() => setShowHeartOverlay(false), 800);
      return;
    }
    lastTap.current = now;
  }, [isLiked, handleLike]);

  const handleComment = useCallback(async (text) => {
    setIsCommenting(true);
    try {
      // Optimistic comment structural mockup
      const tempComment = {
          _id: Date.now().toString(),
          userId: authUser._id,
          fullName: authUser.fullName,
          profilePic: authUser.profilePic,
          role: authUser.role,
          isVerified: authUser.isVerified,
          text: text,
          createdAt: new Date().toISOString()
      };

      setPosts(prev => prev.map(p => p?._id === post._id ? { ...p, comments: [...(p.comments || []), tempComment] } : p));

      const newComment = await commentOnPost(post._id, text);
      
      // Inject actual database record to replace our optimistic mock
      setPosts((prev) =>
        prev.map((p) => {
          if (p?._id === post._id) {
             const cleanComments = (p.comments || []).filter(c => c._id !== tempComment._id);
             return { ...p, comments: [...cleanComments, newComment] };
          }
          return p;
        })
      );
      
      // Force open comments tray if they were closed
      setShowComments(true);
      return true; // Success flag for input box clearer
    } catch {
      toast.error("Failed to add comment");
      return false;
    } finally {
      setIsCommenting(false);
    }
  }, [post._id, authUser, setPosts]);

  const handleShare = useCallback(async () => {
    try {
      const url = `${window.location.origin}/posts?highlight=${post._id}`;
      await navigator.clipboard.writeText(url);
      await sharePost(post._id);
      
      setPosts((prev) =>
        prev.map((p) =>
          p && p._id === post._id
            ? { ...p, shareCount: (p.shareCount || 0) + 1 }
            : p
        )
      );
      toast.success("Link copied!");
    } catch {
      toast.error("Failed to share");
    }
  }, [post._id, setPosts]);

  const handleToggleComments = useCallback(() => setShowComments(s => !s), []);
  const handleToggleSave = useCallback(() => setIsSaved(s => !s), []);
  const handleShowLikedBy = useCallback(() => setLikedByPostId(post._id), [post._id, setLikedByPostId]);

  return (
    <div className="w-full sm:max-w-[470px] mx-auto bg-transparent mb-6 pb-6 border-b border-base-content/10 animate-in fade-in duration-500 will-change-transform">
      <PostHeader 
         post={post}
         authUser={authUser}
         onViewingDP={setViewingDP}
         onDeletePost={handleDelete}
         isDeleting={isDeleting}
      />
      
      <PostMedia 
         post={post}
         onDoubleTap={handleDoubleTap}
         showHeartOverlay={showHeartOverlay}
      />

      <PostActions 
         isLiked={isLiked}
         likeCount={likeCount}
         onLike={handleLike}
         onShare={handleShare}
         onToggleComments={handleToggleComments}
         isSaved={isSaved}
         onToggleSave={handleToggleSave}
         onShowLikedBy={handleShowLikedBy}
      />

      <PostCaption post={post} />

      {/* Quick View comments toggle */}
      {commentCount > 0 && (
        <button 
          onClick={handleToggleComments} 
          className="px-0 text-[14px] text-base-content/50 font-medium hover:text-base-content/70 mb-1 inline-block transition-colors"
        >
          {showComments ? `Hide all comments` : `View all ${commentCount} comments`}
        </button>
      )}

      {/* Expanded Comments Trace */}
      <AnimatePresence>
          {showComments && post.comments?.length > 0 && (
            <motion.div 
               initial={{ opacity: 0, height: 0 }}
               animate={{ opacity: 1, height: "auto" }}
               exit={{ opacity: 0, height: 0 }}
               className="px-0 mt-2 space-y-4 pt-1 overflow-hidden"
            >
              {post.comments.map((comment, index) => (
                <div key={comment._id || `comm-${index}`} className="flex gap-3">
                  <div className="avatar w-8 h-8 rounded-full overflow-hidden flex-shrink-0 cursor-pointer border border-base-content/10">
                    <img src={comment.profilePic || "/avatar.png"} alt={comment.fullName} className="object-cover" loading="lazy" decoding="async" />
                  </div>
                  <div className="flex-1 text-[14px] leading-[18px]">
                    <div className="flex items-center flex-wrap gap-x-1">
                        <span className="font-semibold cursor-pointer hover:opacity-50">{comment.fullName}</span>
                        {(comment.isVerified || comment.role === "admin") && (
                            <div className="flex items-center justify-center shrink-0" title="Verified Professional">
                               <BadgeCheck className="size-3 text-white fill-[#1d9bf0]" strokeWidth={1.5} />
                            </div>
                        )}
                        <span className="break-words ml-0.5">{comment.text}</span>
                    </div>
                    <div className="flex items-center gap-3 mt-1.5 text-xs text-base-content/50 font-medium select-none">
                      <span>{timeAgoShort(comment.createdAt || Date.now())}</span>
                      <button className="hover:opacity-70 font-semibold cursor-pointer">Reply</button>
                    </div>
                  </div>
                  <button className="self-center pr-2">
                    <Heart className="size-3 text-base-content/50 hover:text-base-content cursor-pointer transition-colors" />
                  </button>
                </div>
              ))}
            </motion.div>
          )}
      </AnimatePresence>

      <PostCommentInput 
         onComment={handleComment}
         isCommenting={isCommenting}
      />
    </div>
  );
});
PostCard.displayName = "PostCard";

// === MAIN FEED ROOT ===
const PostsFeed = memo(({ posts, setPosts }) => {
  const { authUser } = useAuthUser();
  const [likedByPostId, setLikedByPostId] = useState(null);
  const [viewingDP, setViewingDP] = useState(null);

  const isPremium = authUser?.role === "admin" || authUser?.isPremium;

  // Render Pipeline Guard
  if (!posts || posts.length === 0) {
    return (
      <div className="text-center py-32 opacity-60">
        <div className="relative inline-block mb-6">
          <MessageSquare className="w-16 h-16 mx-auto opacity-10" />
          <motion.div
            animate={{ scale: [1, 1.2, 1] }}
            transition={{ repeat: Infinity, duration: 3 }}
            className="absolute -top-1 -right-1 size-4 bg-primary rounded-full"
          />
        </div>
        <p className="text-xl font-black italic uppercase tracking-tighter">
          No Posts Yet
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-0 sm:space-y-2">
      {posts.map((post, index) => {
        if (!post) return null;
        return (
          <div key={post._id} className="stagger-item">
            <PostCard
              post={post}
              setPosts={setPosts}
              setLikedByPostId={setLikedByPostId}
              setViewingDP={setViewingDP}
            />
            {/* Professional Ad Injection (Non-Premium Only) */}
            {!isPremium && (index + 1) % 4 === 0 && (
              <div className="max-w-[470px] mx-auto mt-4 sm:mt-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
                <PostAd index={Math.floor(index / 4)} />
              </div>
            )}
          </div>
        );
      })}

      {/* Global Hoisted Modals */}
      <AnimatePresence>
          {likedByPostId && (
            <LikedByModal
              postId={likedByPostId}
              isOpen={true}
              onClose={() => setLikedByPostId(null)}
            />
          )}

          {viewingDP && (
            <ProfilePhotoViewer
              imageUrl={viewingDP.url}
              fullName={viewingDP.name}
              isVerified={viewingDP.isVerified}
              onClose={() => setViewingDP(null)}
            />
          )}
      </AnimatePresence>
    </div>
  );
});
PostsFeed.displayName = "PostsFeed";

export default PostsFeed;

import { useState, useEffect, useRef, useCallback, useMemo, memo } from "react";
import { Link } from "react-router-dom";
import { Heart, MessageCircle, Music, Send, X, BadgeCheck, ExternalLink, Gift, Settings, Maximize, Minimize } from "lucide-react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { likePost, commentOnPost, sharePost, sendGift } from "../lib/api";
import toast from "react-hot-toast";
import { motion, AnimatePresence } from "framer-motion";
import LikedByModal from "./LikedByModal";
import useAuthUser from "../hooks/useAuthUser";
import ReelPlayer from "./reels/ReelPlayer";

/**
 * Standardized Social Reel Card.
 * Heavily optimized with React.memo and decoupled video logic.
 */
const ReelPost = memo(({ post, isActive }) => {
    const { authUser } = useAuthUser();
    const queryClient = useQueryClient();
    const youtubeRef = useRef(null);
    
    // UI State
    const [isPlaying, setIsPlaying] = useState(isActive);
    const [liked, setLiked] = useState(post.likes.includes(authUser?._id));
    const [likesCount, setLikesCount] = useState(post.likes.length);
    const [showComments, setShowComments] = useState(false);
    const [showLikes, setShowLikes] = useState(false);
    const [commentText, setCommentText] = useState("");
    const [isCommenting, setIsCommenting] = useState(false);
    const [isTheaterMode, setIsTheaterMode] = useState(false);
    const [showSpeedMenu, setShowSpeedMenu] = useState(false);
    const [showGifts, setShowGifts] = useState(false);
    const [playbackRate, setPlaybackRate] = useState(1);
    const [showHeart, setShowHeart] = useState(false);

    const lastTap = useRef(0);

    // Synchronize play state with active viewport change
    useEffect(() => {
        setIsPlaying(isActive);
    }, [isActive]);

    // Mutation: Like Logic
    const { mutate: toggleLike } = useMutation({
        mutationFn: () => likePost(post._id),
        onSuccess: (data) => {
            setLiked(data.liked);
            setLikesCount(data.likes.length);
            // Invalidate query to keep global state in sync eventually
            queryClient.invalidateQueries({ queryKey: ["reels"] });
        }
    });

    // Handlers
    const handleDoubleTap = useCallback(() => {
        const now = Date.now();
        if (now - lastTap.current < 300) {
            if (!liked) toggleLike();
            setShowHeart(true);
            setTimeout(() => setShowHeart(false), 800);
            return true;
        }
        lastTap.current = now;
        return false;
    }, [liked, toggleLike]);

    const handleTogglePlay = useCallback(() => {
        if (handleDoubleTap()) return;
        setIsPlaying(prev => !prev);
    }, [handleDoubleTap]);

    const handleShare = useCallback(async () => {
        try {
            const url = `${window.location.origin}/reels?id=${post._id}`;
            await navigator.clipboard.writeText(url);
            await sharePost(post._id);
            toast.success("Link copied!");
        } catch {
            toast.error("Failed to share");
        }
    }, [post._id]);

    const handleComment = useCallback(async () => {
        if (!commentText.trim() || isCommenting) return;
        setIsCommenting(true);
        try {
            const newComment = await commentOnPost(post._id, commentText.trim());
            post.comments.push(newComment); // Local update
            setCommentText("");
            toast.success("Comment added!");
        } catch {
            toast.error("Failed to add comment");
        } finally {
            setIsCommenting(false);
        }
    }, [post._id, post.comments, commentText, isCommenting]);

    const handleSendGift = useCallback(async (gift) => {
        try {
            await sendGift(post.userId, gift.cost, gift.name);
            toast.success(`Sent a ${gift.name}! 🎁`);
            setShowGifts(false);
        } catch (error) {
            toast.error(error.response?.data?.message || "Failed to send gift");
        }
    }, [post.userId]);

    // YouTube Stability Logic
    const getYouTubeUrl = useMemo(() => {
        let baseUrl = post.mediaUrl.split('?')[0];
        const videoId = baseUrl.split('/').pop();
        const origin = window.location.origin;
        return `${baseUrl}?enablejsapi=1&origin=${encodeURIComponent(origin)}&autoplay=0&mute=0&controls=0&loop=1&playlist=${videoId}&modestbranding=1&rel=0&iv_load_policy=3`;
    }, [post.mediaUrl]);

    useEffect(() => {
        if (post.mediaType !== "youtube" || !youtubeRef.current) return;
        
        const command = (isActive && isPlaying) ? 'playVideo' : 'pauseVideo';
        youtubeRef.current.contentWindow?.postMessage(JSON.stringify({
            event: 'command',
            func: command,
            args: ''
        }), 'https://www.youtube.com');
    }, [isActive, isPlaying, post.mediaType]);

    return (
        <div 
            className={`relative h-full w-full bg-black flex items-center justify-center overflow-hidden transition-all duration-500 ${isTheaterMode ? 'sm:max-w-none' : 'sm:max-w-[450px] sm:aspect-[9/16]'}`}
            onClick={handleTogglePlay}
        >
            {/* Media Layer */}
            {post.mediaType === "youtube" ? (
                <div className={`h-full w-full relative transition-all duration-500 bg-black ${isTheaterMode ? 'aspect-video' : 'aspect-[9/16]'}`}>
                    <iframe
                        ref={youtubeRef}
                        src={getYouTubeUrl}
                        className="absolute inset-0 w-full h-full pointer-events-none"
                        allow="autoplay; encrypted-media"
                        title={post.content}
                    />
                </div>
            ) : (
                <ReelPlayer 
                    url={post.mediaUrl} 
                    isActive={isActive && isPlaying} 
                    poster={post.thumbnail}
                />
            )}

            {/* Micro-Interaction Layers */}
            <AnimatePresence>
                {showHeart && (
                    <motion.div
                        initial={{ scale: 0, opacity: 0 }}
                        animate={{ scale: [0, 1.5, 1], opacity: [0, 1, 0] }}
                        className="absolute inset-0 flex items-center justify-center z-50 pointer-events-none"
                    >
                        <Heart className="size-32 text-white fill-white drop-shadow-xl" />
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Sidebar Actions */}
            <div className="absolute right-4 bottom-32 flex flex-col gap-6 items-center z-30" onClick={e => e.stopPropagation()}>
                <div className="flex flex-col items-center gap-1">
                    <button onClick={() => toggleLike()} className={`btn btn-circle btn-ghost bg-black/20 hover:bg-black/40 ${liked ? 'text-red-500' : 'text-white'}`}>
                        <Heart className={`size-7 ${liked ? 'fill-current' : ''}`} />
                    </button>
                    <span className="text-white text-xs font-bold drop-shadow-md">{likesCount}</span>
                </div>

                <div className="flex flex-col items-center gap-1">
                    <button onClick={() => setShowComments(true)} className="btn btn-circle btn-ghost bg-black/20 hover:bg-black/40 text-white">
                        <MessageCircle className="size-7" />
                    </button>
                    <span className="text-white text-xs font-bold drop-shadow-md">{post.comments.length}</span>
                </div>

                <button onClick={() => setShowGifts(!showGifts)} className="btn btn-circle btn-ghost bg-black/20 hover:bg-black/40 text-yellow-400">
                    <Gift className="size-7" />
                </button>

                <button onClick={handleShare} className="btn btn-circle btn-ghost bg-black/20 hover:bg-black/40 text-white">
                    <Send className="size-7" />
                </button>
            </div>

            {/* Info Section */}
            <div className="absolute left-4 bottom-8 right-16 z-30 text-white flex flex-col gap-3 pointer-events-none">
                 <div className="flex items-center gap-3 pointer-events-auto">
                    <Link to={`/user/${post.userId}`} className="flex items-center gap-3 active:scale-95 transition-transform group">
                        <div className="avatar size-10 rounded-full ring-2 ring-primary ring-offset-2 ring-offset-black">
                            <img src={post.profilePic || "/avatar.png"} alt="" className="rounded-full" />
                        </div>
                        <div>
                            <div className="flex items-center gap-1">
                                <h3 className="font-bold text-base drop-shadow-md">@{post.fullName?.replace(/\s+/g, '').toLowerCase()}</h3>
                                {post.isVerified && <BadgeCheck className="size-4 text-white fill-[#1d9bf0]" />}
                            </div>
                            <p className="text-[10px] opacity-60 font-medium">View Profile</p>
                        </div>
                    </Link>
                </div>
                <p className="text-sm line-clamp-2 drop-shadow-md font-medium">{post.content}</p>
                <div className="flex items-center gap-2 bg-black/20 backdrop-blur-md py-1 px-3 rounded-full w-fit">
                    <Music className="size-3 text-primary animate-pulse" />
                    <p className="text-[11px] font-bold">{post.songName || "Original Audio"}</p>
                </div>
            </div>

            {/* Modals & Overlays (Hoisted) */}
            <AnimatePresence>
                {showComments && (
                    <div className="absolute inset-0 z-[100] bg-black/60 backdrop-blur-sm flex flex-col" onClick={e => e.stopPropagation()}>
                        <div className="mt-auto bg-base-100 rounded-t-3xl h-[60%] flex flex-col text-base-content overflow-hidden">
                             <div className="flex justify-between items-center p-4 border-b">
                                <h3 className="font-bold">Comments</h3>
                                <button onClick={() => setShowComments(false)} className="btn btn-ghost btn-circle btn-sm"><X /></button>
                            </div>
                            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                                {post.comments.map((c, i) => (
                                    <div key={i} className="flex gap-2">
                                        <div className="size-8 rounded-full bg-base-200 shrink-0 overflow-hidden">
                                            <img src={c.profilePic || "/avatar.png"} alt="" />
                                        </div>
                                        <div className="bg-base-200 rounded-2xl p-2 px-3 flex-1">
                                            <p className="font-bold text-[10px]">{c.fullName}</p>
                                            <p className="text-xs">{c.text}</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                            <div className="p-4 border-t flex gap-2">
                                <input 
                                    value={commentText} 
                                    onChange={e => setCommentText(e.target.value)} 
                                    type="text" 
                                    placeholder="Add a comment..." 
                                    className="input input-bordered input-sm flex-1 rounded-full" 
                                />
                                <button onClick={handleComment} className="btn btn-primary btn-sm btn-circle"><Send className="size-4" /></button>
                            </div>
                        </div>
                    </div>
                )}
            </AnimatePresence>

            {showLikes && (
                <LikedByModal
                    postId={post._id}
                    isOpen={true}
                    onClose={() => setShowLikes(false)}
                />
            )}
        </div>
    );
});

ReelPost.displayName = "ReelPost";

export default ReelPost;

import { memo, useState, useEffect, useMemo, useCallback } from "react";
import { Link, useLocation } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { useMutation, useQueryClient, useQuery } from "@tanstack/react-query";
import { updateProfile, getCoupleStatus, claimDailyReward } from "../lib/api";
import { APK_DOWNLOAD_URL, downloadFile } from "../lib/axios";
import toast from "react-hot-toast";
import { useTranslation } from "react-i18next";
import useNotificationCounts from "../hooks/useNotificationCounts";
import useAuthUser from "../hooks/useAuthUser";
import {
  Home, Users, HeartHandshake, Crown, Gamepad2, Search, Film, 
  MessageSquare, Smartphone, ShieldAlert, BadgeCheck, Gem, 
  Heart, Sparkles, PlusCircle, Compass, Menu, Zap, DollarSign, Globe, Newspaper, Gift, Trophy
} from "lucide-react";

import CreateStoryModal from "./CreateStoryModal";
import ProfilePhotoViewer from "./ProfilePhotoViewer";
import FocusModeView from "./FocusModeView";
import Logo from "./Logo";
import { logout } from "../lib/api";

// === STATIC CONFIGURATION ===
const staticNavItems = [
  { to: "/", icon: Home, labelKey: "Home" },
  { to: "/search", icon: Search, labelKey: "Search" },
  { to: "/friends", icon: Compass, labelKey: "Explore" },
  { to: "/communities", icon: Users, labelKey: "Communities" },
  { to: "/couple", icon: Sparkles, label: "AI Bestie", isSacred: true },
  { to: "/reels", icon: Film, labelKey: "Reels" },
  { to: "/inbox", icon: MessageSquare, labelKey: "inbox" },
  { to: "/notifications", icon: Heart, labelKey: "notifications" },
  { to: "/games", icon: Gamepad2, labelKey: "Games" },
  { to: "/gem-shop", icon: Crown, labelKey: "Premium" },
  { to: "/prize-vault", icon: Gift, label: "Prize Vault" },
];

// === PERFORMANCE OPTIMIZATION: Memoized Sub-Components ===
// Extracted pure UI components to prevent the entire sidebar from rendering
// when internal counters or dates tick.
const NavBadge = memo(({ count, maxCount = 9 }) => {
  if (!count || count <= 0) return null;
  return (
    <span className="absolute -top-1 -right-1 min-w-[18px] h-[18px] px-1 bg-error text-white text-[11px] font-bold rounded-full flex items-center justify-center ring-2 ring-base-100">
      {count > maxCount ? `${maxCount}+` : count}
    </span>
  );
});
NavBadge.displayName = "NavBadge";

const DailyRewardButton = memo(({ authUser, onClaim }) => {
  if (!authUser) return null;
  const todayStr = new Date().toISOString().split('T')[0];
  const lastClaimDate = authUser.lastRewardClaimDate ? new Date(authUser.lastRewardClaimDate) : null;
  const lastClaimStr = lastClaimDate ? lastClaimDate.toISOString().split('T')[0] : null;

  if (lastClaimStr === todayStr) return null;

  return (
    <button
      className="w-full flex items-center gap-4 p-3 rounded-lg transition-all duration-200 text-purple-500 hover:bg-purple-500/10 group/nav"
      title="Claim Reward"
      onClick={onClaim}
    >
      <div className="relative shrink-0 flex items-center justify-center w-8">
        <div className="absolute inset-0 bg-purple-500/20 rounded-full animate-ping opacity-50"></div>
        <Gem className="size-[26px] stroke-2 group-hover/nav:scale-110 transition-transform" />
      </div>
      <span className="hidden xl:block text-[16px] font-semibold tracking-tight truncate">
        Claim Gems
      </span>
    </button>
  );
});
DailyRewardButton.displayName = "DailyRewardButton";


// === MAIN COMPONENT ===
const Sidebar = memo(() => {
  const { authUser } = useAuthUser();
  const location = useLocation();
  const queryClient = useQueryClient();
  const { t } = useTranslation();
  const { notificationCount, unreadMessages } = useNotificationCounts();
  
  const currentPath = location.pathname;
  
  // Modals state
  const [isStoryModalOpen, setIsStoryModalOpen] = useState(false);
  const [isFocusModalOpen, setIsFocusModalOpen] = useState(false);
  const [viewingDP, setViewingDP] = useState(null);

  // === RETENTION HOOK: Tab Title Optimization ===
  useEffect(() => {
    if (!authUser?._id) return;

    const initialTitle = "Zyro | Master Your Mindset";
    document.title = initialTitle;

    const handleVisibilityChange = () => {
      if (document.hidden) {
        const hooks = [
          "Don't break your streak! 🔥",
          "New Reels for you! 🍿",
          "Claim your daily gems! 💎"
        ];
        document.title = hooks[Math.floor(Math.random() * hooks.length)];
      } else {
        document.title = initialTitle;
      }
    };

    document.addEventListener("visibilitychange", handleVisibilityChange);
    return () => document.removeEventListener("visibilitychange", handleVisibilityChange);
  // Bound to scalar ID rather than auth object to prevent infinite teardown loops
  }, [authUser?._id]);

  // === STABLE CALLBACKS ===
  const handleDownload = useCallback((e) => {
    e.preventDefault();
    downloadFile(`${APK_DOWNLOAD_URL}/latest`, "Zyro_app.apk");
  }, []);

  const handleCreatePost = useCallback(() => {
     window.scrollTo({ top: 0, behavior: 'smooth' });
     toast("Create post is at the top of your feed!", { icon: "✨" });
  }, []);

  const claimReward = useCallback(async () => {
    try {
      const res = await claimDailyReward();
      toast.success(res.message, { icon: '💎' });
      // Single targeted invalidation avoids crashing the query stack
      queryClient.invalidateQueries({ queryKey: ["authUser"] });
    } catch (err) {
      toast.error(err.response?.data?.message || "Wait for tomorrow!");
    }
  }, [queryClient]);

  const { mutate: doUpdate } = useMutation({
    mutationFn: updateProfile,
    onSuccess: (data) => {
      toast.success("Profile photo updated! ✨");
      queryClient.setQueryData(["authUser"], data.user);
      queryClient.invalidateQueries({ queryKey: ["authUser"] });
    },
    onError: (err) => {
      toast.error(err.response?.data?.message || "Failed to update photo");
    }
  });

  const handleLogout = useCallback(async () => {
    try {
      await logout();
      queryClient.setQueryData(["authUser"], null);
      window.location.href = "/login";
    } catch (err) {
      toast.error("Logout failed. Try clearing cache.");
    }
  }, [queryClient]);

  const handleDPUpdate = useCallback(async (base64) => {
    await doUpdate({ profilePic: base64 });
    setViewingDP(null);
  }, [doUpdate]);

  // Couple Relationship status stream
  const { data: coupleData } = useQuery({
    queryKey: ["coupleStatus"],
    queryFn: getCoupleStatus,
    enabled: !!authUser?._id,
    staleTime: 1000 * 60 * 10
  });

  const isCoupled = coupleData?.coupleStatus === "coupled";
  const partnerId = coupleData?.partner?._id;

  // === DATA MEMOIZATION ===
  // Prevents recreation of 14 complex Nav Objects containing Lucide SVG bindings on every scroll/keystroke.
  const dynamicNavItems = useMemo(() => {
    const items = staticNavItems.map(item => ({
      ...item,
      id: `tour-${item.labelKey?.toLowerCase() || item.label?.toLowerCase().replace(/\s+/g, '-')}`
    }));

    return items;
  }, [isCoupled, partnerId]);

  return (
    <aside className="w-[80px] xl:w-[244px] hidden md:flex flex-col h-screen fixed top-0 left-0 border-r border-base-content/10 bg-base-100 z-50 overflow-hidden transition-all duration-300">
      
      {/* Brand area */}
      <div className="pt-8 pb-6 px-4 xl:px-6 flex justify-center xl:justify-start">
        <div className="hidden xl:block">
          <Logo showText={true} fontSize="text-2xl" />
        </div>
        <div className="xl:hidden">
          <Logo showText={false} />
        </div>
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-3 py-2 space-y-1 overflow-y-auto custom-scrollbar">
        {dynamicNavItems.map(({ to, icon: Icon, labelKey, isSacred, label: directLabel, id }) => {
          const isActive = currentPath === to;
          const displayLabel = isSacred || directLabel ? (directLabel) : t(labelKey) || labelKey;

          return (
            <Link
              key={to}
              to={to}
              id={id}
              className={`flex items-center gap-4 p-3 rounded-lg transition-all duration-200 group/nav ${
                isActive ? "font-bold text-base-content bg-base-content/5" : "text-base-content hover:bg-base-content/5"
              }`}
              title={displayLabel}
            >
              <div className="relative shrink-0 flex items-center justify-center w-8">
                <Icon
                  className={`size-[26px] transition-transform duration-200 group-hover/nav:scale-105 ${
                    isActive && labelKey !== "Search" ? "stroke-[2.5px]" : "stroke-2 opacity-90"
                  } ${isSacred ? "text-pink-500" : ""}`}
                  // Optimization: Directly binding fill to currentColor eliminates expensive CSS specificity overwrites
                  fill={isActive && labelKey !== "Search" && labelKey !== "Explore" ? "currentColor" : "none"}
                />
                
                {labelKey === "inbox" && <NavBadge count={unreadMessages} />}
                {labelKey === "notifications" && <NavBadge count={notificationCount} />}
              </div>
              <span className={`hidden xl:block text-[16px] tracking-tight truncate ${isActive ? "" : "opacity-90"} ${isSacred ? "text-pink-500 font-semibold" : ""}`}>
                {displayLabel}
              </span>
            </Link>
          );
        })}

        {/* Create Post Button */}
        <button
          onClick={handleCreatePost}
          id="tour-create"
          className="flex w-full items-center gap-4 p-3 rounded-lg transition-all duration-200 text-base-content hover:bg-base-content/5 group/nav"
          title="Create"
        >
          <div className="relative shrink-0 flex items-center justify-center w-8">
            <PlusCircle className="size-[26px] stroke-2 opacity-90 transition-transform duration-200 group-hover/nav:scale-105" />
          </div>
          <span className="hidden xl:block text-[16px] tracking-tight truncate opacity-90">
            Create
          </span>
        </button>

        {/* Profile Link */}
        <Link
          to="/profile"
          id="tour-profile"
          className={`flex items-center gap-4 p-3 rounded-lg transition-all duration-200 group/nav ${
            currentPath === "/profile" ? "font-bold text-base-content bg-base-content/5" : "text-base-content hover:bg-base-content/5"
          }`}
          title="Profile"
        >
          <div className="relative shrink-0 flex items-center justify-center w-8">
             <div className={`size-7 rounded-full overflow-hidden shrink-0 bg-base-300 transition-transform duration-200 group-hover/nav:scale-105 ${
               currentPath === "/profile" ? "ring-2 ring-base-content ring-offset-2 ring-offset-base-100" : ""
             }`}>
                 <img
                    src={authUser?.profilePic || "/avatar.png"}
                    alt="Profile"
                    className="w-full h-full object-cover"
                    loading="lazy"
                    decoding="async"
                 />
             </div>
             {(authUser?.isVerified || authUser?.role === "admin") && (
                <div className="absolute -bottom-1 -right-1 size-3.5 bg-white rounded-full flex items-center justify-center p-[1px] shadow-sm ring-1 ring-base-content/5 overflow-hidden">
                   <BadgeCheck className="size-full text-white fill-[#1d9bf0]" strokeWidth={2} />
                </div>
             )}
          </div>
          <span className={`hidden xl:block text-[16px] tracking-tight truncate ${currentPath === "/profile" ? "" : "opacity-90"}`}>
            Profile
          </span>
        </Link>
        
        {/* Admin Link */}
        {authUser?.role === "admin" && (
          <Link
            to="/admin"
            className={`flex items-center gap-4 p-3 rounded-lg transition-all duration-200 group/nav mt-4 bg-primary/10 ${
              currentPath === "/admin" ? "font-bold text-primary" : "text-primary hover:bg-primary/20"
            }`}
            title="Admin"
          >
            <div className="relative shrink-0 flex items-center justify-center w-8">
              <ShieldAlert className="size-[24px] stroke-2 transition-transform duration-200 group-hover/nav:scale-105" />
            </div>
            <span className="hidden xl:block text-[16px] tracking-tight truncate">
              {t('admin_command') || "Admin"}
            </span>
          </Link>
        )}
      </nav>

      {/* DAILY REWARDS & BOTTOM ACTIONS */}
      <div className="px-3 pb-6 pt-2 space-y-2 mt-auto">
      
        {/* Memoized Daily Reward Integration */}
        {authUser && <DailyRewardButton authUser={authUser} onClaim={claimReward} />}

        {/* Watch Tutorial */}
        <button
          onClick={() => window.dispatchEvent(new CustomEvent("Zyro_start_tutorial"))}
          className="flex w-full items-center gap-4 p-3 rounded-lg transition-all duration-200 text-base-content opacity-70 hover:opacity-100 hover:bg-base-content/5 group/nav"
          title="Watch Tutorial"
        >
          <div className="relative shrink-0 flex items-center justify-center w-8">
            <Sparkles className="size-[26px] stroke-2 text-primary group-hover/nav:scale-105 transition-transform" />
          </div>
          <span className="hidden xl:block text-[16px] tracking-tight truncate">
            Help & Tutorial
          </span>
        </button>

        {/* Download App */}
        <a
          href={`${APK_DOWNLOAD_URL}/latest`}
          onClick={handleDownload}
          className="flex items-center gap-4 p-3 rounded-lg transition-all duration-200 text-base-content opacity-70 hover:opacity-100 hover:bg-base-content/5 group/nav"
          title="Download App"
        >
          <div className="relative shrink-0 flex items-center justify-center w-8">
            <Smartphone className="size-[26px] stroke-2 group-hover/nav:scale-105 transition-transform" />
          </div>
          <span className="hidden xl:block text-[16px] tracking-tight truncate">
            Get App
          </span>
        </a>

        {/* Menu (More) — Optimized with Premium Dropdown */}
        <div className="dropdown dropdown-top dropdown-end w-full">
          <label 
            tabIndex={0} 
            className="flex w-full items-center gap-4 p-3 rounded-lg transition-all duration-200 text-base-content hover:bg-base-content/5 group/nav cursor-pointer"
          >
            <div className="relative shrink-0 flex items-center justify-center w-8">
              <Menu className="size-[26px] stroke-2 opacity-90 transition-transform duration-200 group-hover/nav:scale-105" />
            </div>
            <span className="hidden xl:block text-[16px] tracking-tight truncate opacity-90 font-medium">
              More
            </span>
          </label>
          <ul tabIndex={0} className="dropdown-content z-[60] menu p-2 shadow-2xl bg-base-100 border border-base-content/10 rounded-2xl w-64 mb-4 animate-in fade-in slide-in-from-bottom-2 duration-300">
            <li className="menu-title px-4 py-2 opacity-40 text-[10px] uppercase font-black tracking-widest">Bond OS Menu</li>
            
            <li>
              <Link to="/creator-center" className="flex items-center gap-3 p-3 rounded-xl hover:bg-emerald-500/10 text-emerald-500 font-bold">
                <DollarSign className="size-5 fill-emerald-500/20" />
                Creator Monetization
              </Link>
            </li>
            
            <li>
              <Link to="/antigravity-engine" className="flex items-center gap-3 p-3 rounded-xl hover:bg-blue-500/10 text-blue-500 font-bold">
                <Globe className="size-5 fill-blue-500/20" />
                Antigravity Engine
              </Link>
            </li>

            <li>
              <button 
                onClick={() => setIsFocusModalOpen(true)}
                className="flex items-center gap-3 p-3 rounded-xl hover:bg-primary/10 text-primary font-bold"
              >
                <Zap className="size-5 fill-primary/20" />
                AI Career Focus Mode
              </button>
            </li>

            <li>
              <Link to="/settings" className="flex items-center gap-3 p-3 rounded-xl">
                 <BadgeCheck className="size-5 text-info" />
                 Verification & Settings
              </Link>
            </li>

            <div className="divider my-0 opacity-5"></div>

            <li>
              <button 
                onClick={handleLogout}
                className="flex items-center gap-3 p-3 rounded-xl text-error hover:bg-error/10"
              >
                Logout Account
              </button>
            </li>
          </ul>
        </div>
      </div>

      <CreateStoryModal
        isOpen={isStoryModalOpen}
        onClose={() => setIsStoryModalOpen(false)}
      />

      {/* AI Career Focus Mode Modal */}
      <AnimatePresence>
        {isFocusModalOpen && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setIsFocusModalOpen(false)}
              className="absolute inset-0 bg-black/60 backdrop-blur-sm"
            />
            <motion.div
              initial={{ opacity: 0, scale: 0.9, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.9, y: 20 }}
              className="relative w-full max-w-xl z-10"
            >
               <button 
                 onClick={() => setIsFocusModalOpen(false)}
                 className="absolute -top-12 right-0 text-white opacity-50 hover:opacity-100 font-bold bg-white/10 px-4 py-2 rounded-full"
               >
                 Close Esc
               </button>
               <FocusModeView />
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {viewingDP && (
        <ProfilePhotoViewer
          imageUrl={viewingDP.url}
          fullName={viewingDP.name}
          isVerified={authUser?.isVerified || authUser?.role === "admin"}
          onClose={() => setViewingDP(null)}
          onUpdate={handleDPUpdate}
        />
      )}
    </aside>
  );
});

Sidebar.displayName = "Sidebar";
export default Sidebar;

import { memo, useState, useCallback, useMemo } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { getStories, deleteStory } from "../lib/api";
import { Plus, BadgeCheck } from "lucide-react";
import StoryViewer from "./StoryViewer";
import useAuthUser from "../hooks/useAuthUser";
import CreateStoryModal from "./CreateStoryModal";
import { StorySkeleton } from "./Skeletons";

// === PERFORMANCE OPTIMIZATION: Memoized Sub-Components ===
// Extracted the "Add Story" button to prevent unnecessary re-rendering
// when other friends' stories load or change.
const AddStoryButton = memo(({ authUser, onOpenModal }) => {
    return (
        <div className="flex flex-col items-center gap-2 min-w-[72px] group relative select-none">
            <button
                onClick={onOpenModal}
                className="relative size-[66px] rounded-full p-[3px] transition-all duration-300 active:scale-95"
                aria-label="Create a new story"
            >
                <div className="size-full rounded-full overflow-hidden bg-base-300 ring-[1px] ring-base-content/10">
                    <img
                        src={authUser?.profilePic || "/avatar.png"}
                        alt={authUser?.fullName || "Me"}
                        className="size-full object-cover group-hover:scale-105 transition-transform duration-500"
                        loading="lazy"
                        decoding="async"
                    />
                </div>
                {/* Instagram-style blue plus badge */}
                <div className="absolute bottom-1 right-1 size-5 bg-white rounded-full border-[2.5px] border-base-100 shadow-sm flex items-center justify-center translate-x-1 translate-y-1 z-10 overflow-hidden">
                    {authUser?.isVerified || authUser?.role === "admin" ? (
                        <BadgeCheck className="size-full text-white fill-[#1d9bf0]" strokeWidth={2} />
                    ) : (
                        <div className="size-full bg-[#0095f6] flex items-center justify-center">
                            <Plus className="size-3 text-white" strokeWidth={4} />
                        </div>
                    )}
                </div>
                {/* Subtle hover overlay */}
                <div className="absolute inset-[3px] rounded-full bg-black/0 group-hover:bg-black/5 transition-colors duration-300" />
            </button>
            <span className="text-[11px] font-medium opacity-60 tracking-tight">Your story</span>
        </div>
    );
});
AddStoryButton.displayName = "AddStoryButton";

// === REUSABLE STORY AVATAR CARD ===
// Decoupled heavily-styled DOM elements from the main iteration loop
const StoryItem = memo(({ group, currentUserId, onSelect }) => {
    // Prevent inline function recreation inside array map loops
    const handleClick = useCallback(() => {
        onSelect(group);
    }, [group, onSelect]);

    const isCurrentUser = group.userId === currentUserId;
    const displayName = isCurrentUser ? "your story" : group.fullName.split(" ")[0].toLowerCase();
    const isVerified = group.role === "admin" || group.isVerified;

    return (
        <div
            className="flex flex-col items-center gap-2 cursor-pointer min-w-[72px] group/story select-none"
            onClick={handleClick}
            role="button"
            aria-label={`View ${displayName}'s story`}
        >
            {/* CSS Gradient Story Circle */}
            <div className="relative size-[66px] rounded-full p-[3px] bg-gradient-to-tr from-amber-400 via-orange-500 to-rose-600 transition-transform duration-300 active:scale-95 ring-[1px] ring-base-content/5">
                <div className="size-full rounded-full border-[2.5px] border-base-100 overflow-hidden bg-base-300 shrink-0">
                    <img
                        src={group.profilePic || "/avatar.png"}
                        alt={group.fullName}
                        className="size-full object-cover group-hover/story:scale-105 transition-transform duration-500"
                        loading="lazy"
                        decoding="async"
                    />
                </div>
                {/* Verification Overlay */}
                {isVerified && (
                    <div className="absolute bottom-1 right-1 size-5 bg-white rounded-full border-[2.5px] border-base-100 shadow-sm flex items-center justify-center translate-x-1 translate-y-1 z-10">
                        <BadgeCheck className="size-full text-white fill-[#1d9bf0]" strokeWidth={2} />
                    </div>
                )}
            </div>
            {/* Text Label */}
            <span className="text-[11px] font-medium truncate w-[72px] text-center opacity-60 tracking-tight group-hover/story:opacity-100 transition-opacity whitespace-nowrap px-1">
                {displayName}
            </span>
        </div>
    );
});
StoryItem.displayName = "StoryItem";

// === MAIN TRAY COMPONENT ===
const StoryTray = memo(() => {
    const { authUser } = useAuthUser();
    const queryClient = useQueryClient();

    // Modal & Viewer UI State
    const [selectedUserStories, setSelectedUserStories] = useState(null);
    const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);

    // === OPTIMIZED CACHING ===
    // Configured staleTime preventing constant background refetches when navigating between feeds/profiles
    const { data: storiesGrouped = [], isLoading } = useQuery({
        queryKey: ["stories"],
        queryFn: getStories,
        staleTime: 1000 * 60, // Consider stories fresh for 1 minute
        refetchOnWindowFocus: true // Auto-refresh if they switch tabs and come back
    });

    // === STABLE HANDLERS ===
    const openCreateModal = useCallback(() => setIsCreateModalOpen(true), []);
    const closeCreateModal = useCallback(() => setIsCreateModalOpen(false), []);
    const closeViewer = useCallback(() => setSelectedUserStories(null), []);

    // Separated the selection function to prevent recreating the entire array map loop
    const handleSelectStory = useCallback((group) => {
        setSelectedUserStories(group);
    }, []);

    // Extracted async delete handler utilizing React Query invalidation
    const handleDelete = useCallback(async (storyId) => {
        try {
            await deleteStory(storyId);
            // Targeted invalidation forces a strict UI refresh automatically bridging with cache
            queryClient.invalidateQueries({ queryKey: ["stories"] });
            
            // Note: StoryViewer handles closing itself if it was the last story
        } catch (err) {
            console.error("Delete story error:", err);
        }
    }, [queryClient]);

    return (
        <div className="flex items-center gap-4 overflow-x-auto pb-4 no-scrollbar scroll-smooth min-h-[100px] w-full relative">
            
            {/* 1. Add Story Button (Always Visible & Memoized) */}
            <AddStoryButton 
                authUser={authUser} 
                onOpenModal={openCreateModal} 
            />

            {/* 2. Loading State vs Real Stories */}
            {isLoading ? (
                <StorySkeleton />
            ) : (
                storiesGrouped.map((group) => (
                    <StoryItem 
                        key={group.userId} 
                        group={group} 
                        currentUserId={authUser?._id}
                        onSelect={handleSelectStory}
                    />
                ))
            )}

            {/* 3. Global Creation & Viewer Modals */}
            <CreateStoryModal
                isOpen={isCreateModalOpen}
                onClose={closeCreateModal}
            />

            {selectedUserStories && (
                <StoryViewer
                    group={selectedUserStories}
                    onClose={closeViewer}
                    onDelete={handleDelete}
                />
            )}
        </div>
    );
});

StoryTray.displayName = "StoryTray";
export default StoryTray;

import { useState, useEffect, useCallback, useRef, memo } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { X, Trash2, ChevronLeft, ChevronRight, Eye, Heart, MessageCircle, Send, BadgeCheck } from "lucide-react";
import toast from "react-hot-toast";
import ProfilePhotoViewer from "./ProfilePhotoViewer";
import { viewStory, likeStory, commentOnStory } from "../lib/api";
import useAuthUser from "../hooks/useAuthUser";

// === SUBCOMPONENT: Story Header (Progress Bars & Identity) ===
// Optimization: Extracted so the rapid `progress` timer updates (every 300ms)
// only re-render this top bar, rather than the entire Viewport and heavy Video elements.
const StoryHeader = memo(({ group, currentIndex, progress, isOwner, story, onPause, onViewDP, onShowViewers, onDelete, onClose }) => {
    return (
        <div className="absolute top-0 inset-x-0 z-50 p-4 sm:p-5 bg-gradient-to-b from-black/80 via-black/40 to-transparent pointer-events-none">
            <div className="w-full h-full pointer-events-auto">
