                            className="size-9 rounded-full p-[2px] bg-gradient-to-tr from-orange-400 via-pink-500 to-purple-500 cursor-pointer active:scale-95 transition-transform shrink-0"
                            onClick={(e) => {
                                e.stopPropagation();
                                onPause();
