    return (
        <AnimatePresence>
            <div 
                className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm" 
                role="dialog" 
                aria-modal="true" 
                aria-labelledby="friends-modal-title"
                onKeyDown={(e) => e.key === "Escape" && onClose()}
            >
                <motion.div
                    variants={modalVariants}
                    initial="hidden"
