                            </div>
                        </div>
                        <button 
                            onClick={onClose} 
                            className="btn btn-ghost btn-sm btn-circle active:scale-90 transition-transform focus:ring-2 focus:ring-primary/40 shrink-0" 
                            aria-label="Close modal"
                            tabIndex={0}
                        >
                            <X className="size-5" />
