import React, { createContext, useContext, useState, useEffect, useRef } from "react";

const ModeContext = createContext();

export const ModeProvider = ({ children }) => {
    const [appMode, setAppMode] = useState(() => {
        return localStorage.getItem("app_mode") || "fantasy";
    });
    const [isRebooting, setIsRebooting] = useState(false);

    const toggleMode = () => {
        if (isRebooting) return; // Guard against rapid toggling

        setIsRebooting(true);
        const newMode = appMode === "social" ? "fantasy" : "social";
        
        // Delay the actual state switch to allow the glitch animation to play
        setTimeout(() => {
            setAppMode(newMode);
            localStorage.setItem("app_mode", newMode);
            setIsRebooting(false);
        }, 600);
        
        // Haptic Feedback (Premium Feel)
        if (window.navigator.vibrate) {
            window.navigator.vibrate([30, 10, 30]);
        }

        // Play subtle whoosh sound
        try {
            const audio = new Audio("https://assets.mixkit.co/active_storage/sfx/2568/2568-preview.mp3");
            audio.volume = 0.2;
            audio.play();
        } catch (e) {
            console.log("Audio play blocked");
        }
    };

    // --- SHAKE TO SWITCH ---
    const shakeRef = useRef({
        lastX: undefined,
        lastY: undefined,
        lastZ: undefined,
        lastShake: 0
    });

    useEffect(() => {
        let threshold = 40; // Increased shake sensitivity threshold

        const handleMotion = (e) => {
            const now = Date.now();
            if (now - shakeRef.current.lastShake < 2000) return; // 2s cooldown between shakes

            let acc = e.accelerationIncludingGravity;
            if (!acc) return;

            const { lastX, lastY, lastZ } = shakeRef.current;

            if (lastX !== undefined) {
                let deltaX = Math.abs(acc.x - lastX);
                let deltaY = Math.abs(acc.y - lastY);
                let deltaZ = Math.abs(acc.z - lastZ);

                if ((deltaX > threshold && deltaY > threshold) || 
                    (deltaX > threshold && deltaZ > threshold) || 
                    (deltaY > threshold && deltaZ > threshold)) {
                    shakeRef.current.lastShake = now;
                    toggleMode();
                }
            }

            shakeRef.current.lastX = acc.x;
            shakeRef.current.lastY = acc.y;
            shakeRef.current.lastZ = acc.z;
        };

        if (window.DeviceMotionEvent) {
            window.addEventListener('devicemotion', handleMotion);
        }
        return () => window.removeEventListener('devicemotion', handleMotion);
    }, [toggleMode]); // Only depends on toggleMode

    // --- THEME INJECTION ---
    useEffect(() => {
        const root = document.documentElement;
        document.body.setAttribute("data-mode", appMode);

        if (appMode === 'fantasy') {
            // Neon / High-Octane Themes
            root.style.setProperty('--mode-primary', '#F97316'); // Orange
            root.style.setProperty('--mode-secondary', '#7C3AED'); // Violet
            root.style.setProperty('--mode-bg', '#0F172A'); // Dark Blue Slate
            root.style.setProperty('--mode-glow', 'rgba(249, 115, 22, 0.4)');
            root.style.setProperty('--mode-card', 'rgba(30, 41, 59, 0.7)');
        } else {
            // Clean / Minimalist Social Themes
            root.style.setProperty('--mode-primary', '#6366F1'); // Indigo
            root.style.setProperty('--mode-secondary', '#EC4899'); // Pink
            root.style.setProperty('--mode-bg', '#000000'); // Pure Black (Glassmorphism pop)
            root.style.setProperty('--mode-glow', 'rgba(99, 102, 241, 0.4)');
            root.style.setProperty('--mode-card', 'rgba(255, 255, 255, 0.05)');
        }
    }, [appMode]);

    return (
        <ModeContext.Provider value={{ appMode, toggleMode, isRebooting }}>
            {children}
        </ModeContext.Provider>
    );
};

export const useAppMode = () => {
    const context = useContext(ModeContext);
    if (!context) {
        throw new Error("useAppMode must be used within a ModeProvider");
    }
    return context;
};

import React, { createContext, useContext, useEffect, useCallback } from "react";
import { useThemeStore } from "../store/useThemeStore";

const ThemeContext = createContext();

/**
 * Team Theme Configuration
 * Map of IPL teams to their primary 'Antigravity' color palettes.
 */
const TEAM_THEMES = {
    CSK: { primary: "#F9CD05", secondary: "#0081E5", accent: "#F9CD05" },
    RCB: { primary: "#EC1C24", secondary: "#2B2A29", accent: "#EC1C24" },
    MI: { primary: "#004BA0", secondary: "#D1AB3E", accent: "#004BA0" },
    KKR: { primary: "#2E0854", secondary: "#B3A123", accent: "#2E0854" },
    GT: { primary: "#1B2133", secondary: "#F0DFAD", accent: "#1B2133" },
    LSG: { primary: "#3D38BA", secondary: "#E86FBD", accent: "#3D38BA" },
    RR: { primary: "#EA1A85", secondary: "#254AA5", accent: "#EA1A85" },
    DC: { primary: "#004C93", secondary: "#EF4123", accent: "#004C93" },
    PBKS: { primary: "#ED1B24", secondary: "#D1AB3E", accent: "#ED1B24" },
    SRH: { primary: "#F26522", secondary: "#000000", accent: "#F26522" },
    DEFAULT: { primary: "#6366f1", secondary: "#8b5cf6", accent: "#6366f1" }
};

export const ThemeProvider = ({ children }) => {
    const { theme, setTheme } = useThemeStore();

    const applyTeamTheme = useCallback((teamCode) => {
        const colors = TEAM_THEMES[teamCode] || TEAM_THEMES.DEFAULT;
        
        // Inject CSS Variables directly into Document Root for 'Antigravity' speed
        const root = document.documentElement;
        root.style.setProperty("--primary-color", colors.primary);
        root.style.setProperty("--secondary-color", colors.secondary);
        root.style.setProperty("--accent-color", colors.accent);
        
        // Also sync with the base UI theme if needed
        console.log(`📡 [Theme Engine] Team Theme Applied: ${teamCode}`);
    }, []);

    // Effect to apply theme on load or change
    useEffect(() => {
        document.documentElement.setAttribute("data-theme", theme);
    }, [theme]);

    return (
        <ThemeContext.Provider value={{ theme, setTheme, applyTeamTheme }}>
            {children}
        </ThemeContext.Provider>
    );
};

export const useGlobalTheme = () => {
    const context = useContext(ThemeContext);
    if (!context) {
        throw new Error("useGlobalTheme must be used within a ThemeProvider");
    }
    return context;
};

import { useEffect, useRef, useState } from "react";

/**
 * useIntersection - A professional hook for infinite scrolling and lazy loading.
 * @param {Object} options - IntersectionObserver options (root, rootMargin, threshold)
 * @returns {[RefObject, boolean]} - [the ref to observe, isIntersecting state]
 */
export const useIntersection = (options = { threshold: 0.1, rootMargin: "0px" }) => {
    const [isIntersecting, setIsIntersecting] = useState(false);
    const elementRef = useRef(null);

    useEffect(() => {
        const element = elementRef.current;
        if (!element) return;

        const observer = new IntersectionObserver(([entry]) => {
            setIsIntersecting(entry.isIntersecting);
        }, options);

        observer.observe(element);
        return () => observer.unobserve(element);
    }, [options.threshold, options.rootMargin, options.root]);

    return [elementRef, isIntersecting];
};

import { processPaymentVerification } from "./paymentAPI";

/**
 * Initializes and mounts the Razorpay checkout modal widget safely on the client window.
 * Decoupled from React to ensure pure JS execution isolated from Virtual DOM updates.
 */
export const launchRazorpayCheckout = ({
    key,
    order,
    authUser,
    onSuccess,
    onError,
    onCancel
}) => {
    if (!window.Razorpay) {
        return onError("Payment gateway not loaded. Please refresh the page and try again.");
    }

    const options = {
        key,
        amount: order.amount,
        currency: order.currency,
        name: "Zyro Premium",
        description: "Monthly Premium Membership — ₹49/month",
        order_id: order.id,
        handler: async (response) => {
            try {
                // Perform secure signature verifications
                await processPaymentVerification(response);
                onSuccess(response);
            } catch (err) {
                onError("Payment verification failed. Your money is safe and will be refunded if deducted. Please contact support.");
            }
        },
        prefill: {
            name: authUser?.fullName || "",
            email: authUser?.email || "",
        },
        theme: {
            color: "#6366f1",
        },
        modal: {
            ondismiss: onCancel,
        },
        retry: {
            enabled: false // Disable default retry to handle custom error UI mapping directly
        }
    };

    const rzp = new window.Razorpay(options);

    rzp.on("payment.failed", (response) => {
        let msg = response.error.description || "Unknown error occurred.";
        if (msg.toLowerCase().includes("merchant")) {
            msg = "Platform configuration issue. Please contact support.";
        }
        onError(`Payment declined: ${msg}`);
        // Log secure details to your error catching platform silently here
        console.error("[Razorpay Error]", response.error);
    });

    rzp.open();
};

/**
