                                                <span className="font-black italic uppercase tracking-tighter text-lg">Transmit signal</span>
                                                <Send className="size-6 group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
                                            </>
                                        )}
                                    </button>
