import { useState, useEffect } from "react";
import { useParams, Link } from "react-router-dom";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { getCommunityDetails, getCommunityPosts, toggleJoinCommunity, createCommunityPost } from "../lib/api";
import { Users, Lock, ChevronLeft, Image as ImageIcon, Sparkles } from "lucide-react";
import toast from "react-hot-toast";
import useAuthUser from "../hooks/useAuthUser";
import PostsFeed from "../components/PostsFeed";

export default function CommunityDetailsPage() {
  const { id } = useParams();
  const { authUser } = useAuthUser();
  const queryClient = useQueryClient();
  const [content, setContent] = useState("");
  const [media, setMedia] = useState(null);

  const { data: cData, isLoading: isCommLoading } = useQuery({
    queryKey: ["community", id],
    queryFn: () => getCommunityDetails(id),
  });

  const { data: pData, isLoading: isPostsLoading } = useQuery({
    queryKey: ["community-posts", id],
    queryFn: () => getCommunityPosts(id),
  });

  const [localPosts, setLocalPosts] = useState([]);
  const community = cData?.community;
  const posts = pData?.posts || [];

  // Sync react-query data to local state for optimistic updates
  useEffect(() => {
    if (posts) setLocalPosts(posts);
  }, [posts]);

  const joinMutation = useMutation({
    mutationFn: toggleJoinCommunity,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["community", id] });
      queryClient.invalidateQueries({ queryKey: ["communities"] });
      toast.success("Community status updated");
    },
    onError: () => toast.error("Action failed"),
  });

  const postMutation = useMutation({
    mutationFn: (data) => createCommunityPost(id, data),
    onSuccess: () => {
      setContent("");
      setMedia(null);
      queryClient.invalidateQueries({ queryKey: ["community-posts", id] });
      toast.success("Posted to community!");
    },
    onError: () => toast.error("Failed to post"),
  });

  const handleMediaUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 20 * 1024 * 1024) return toast.error("File size must be less than 20MB");
      const reader = new FileReader();
      reader.onload = () => setMedia({ url: reader.result, type: file.type.startsWith("video") ? "video" : "image" });
      reader.readAsDataURL(file);
    }
  };

  const handlePostSubmit = (e) => {
    e.preventDefault();
    if (!content.trim() && !media) return toast.error("Post cannot be empty");
    postMutation.mutate({ content, media: media?.url, mediaType: media?.type });
  };

  if (isCommLoading) return <div className="p-10 text-center text-white/50">Loading community...</div>;
  if (!community) return <div className="p-10 text-center text-red-500">Community not found</div>;

  const isMember = community.members.some(m => m._id === authUser?._id);
  const canViewFeed = !community.isPrivate || isMember;

  return (
    <div className="max-w-2xl mx-auto w-full pb-20 font-outfit min-h-screen bg-base-100 text-base-content">
      {/* Header Banner */}
      <div className="h-48 md:h-64 relative bg-base-300 overflow-hidden">
        {community.banner ? (
          <img src={community.banner} alt={community.name} className="w-full h-full object-cover opacity-60" />
        ) : (
          <div className="w-full h-full bg-gradient-to-br from-primary/30 to-secondary/30 opacity-60"></div>
        )}
        <Link to="/communities" className="absolute top-4 left-4 p-2 bg-base-100/50 rounded-full hover:bg-base-100 transition-colors text-base-content backdrop-blur-md border border-base-content/10">
          <ChevronLeft size={24} />
        </Link>
      </div>

      <div className="px-4 pb-4 md:px-6 relative -mt-16">
        <div className="flex items-end justify-between mb-4">
          <div className="w-32 h-32 rounded-3xl bg-base-200 border-4 border-base-100 overflow-hidden flex items-center justify-center shrink-0 shadow-2xl">
             {community.icon ? <img src={community.icon} alt="icon" className="w-full h-full object-cover" /> : <Users className="text-base-content/30 w-12 h-12" />}
          </div>
          <div className="flex gap-2">
            <button
               onClick={() => joinMutation.mutate(community._id)}
               disabled={joinMutation.isPending}
               className={`px-6 py-2.5 rounded-full font-bold transition-all shadow-lg ${
                 isMember 
                 ? "bg-base-content/10 text-base-content hover:bg-red-500/20 hover:text-red-400 border border-base-content/20" 
                 : "bg-primary text-primary-content hover:opacity-90 hover:scale-105"
               }`}
            >
               {joinMutation.isPending ? "..." : isMember ? "Joined" : "Join Community"}
            </button>
          </div>
        </div>

        <div>
          <h1 className="text-3xl font-extrabold text-base-content flex items-center gap-2">
            {community.name}
            {community.isPrivate && <Lock size={20} className="text-base-content/40" title="Private Community" />}
          </h1>
          <p className="text-base-content/70 mt-3 text-lg leading-relaxed">{community.description}</p>
          <div className="flex items-center gap-4 mt-4 text-base-content/50 text-sm font-medium">
            <span className="flex items-center gap-1.5 bg-base-content/5 px-3 py-1.5 rounded-lg border border-base-content/5"><Users size={16} /> {community.members.length} Members</span>
            <span className="flex items-center gap-1.5 bg-base-content/5 px-3 py-1.5 rounded-lg border border-base-content/5">Created by <span className="text-primary ml-1">{community.creatorId?.fullName}</span></span>
          </div>
        </div>
      </div>

      <div className="mt-6 border-t border-base-content/10"></div>

      <div className="px-4 md:px-6 pt-6">
        {canViewFeed ? (
          <>
            {/* Create Post Input */}
            <form onSubmit={handlePostSubmit} className="mb-8 bg-base-content/5 border border-base-content/10 rounded-2xl p-4 shadow-xl">
              <div className="flex gap-3">
                <img src={authUser?.profilePic} alt="avatar" className="w-10 h-10 rounded-full object-cover border border-base-content/20 shrink-0" />
                <div className="flex-1">
                  <textarea 
                    value={content} onChange={e => setContent(e.target.value)}
                    placeholder={`Post to ${community.name}...`}
                    className="w-full bg-transparent text-base-content outline-none resize-none pt-2 text-lg placeholder:text-base-content/40"
                    rows={content.length > 50 ? 3 : 1}
                  />
                  {media && (
                    <div className="relative mt-3 rounded-xl overflow-hidden border border-white/20 bg-black/50">
                      <button type="button" onClick={() => setMedia(null)} className="absolute top-2 right-2 w-8 h-8 bg-black/60 rounded-full text-white flex items-center justify-center hover:bg-red-500/80 backdrop-blur-md z-10 transition-colors">✕</button>
                      {media.type === "video" ? <video src={media.url} controls className="w-full max-h-80 object-contain" /> : <img src={media.url} alt="upload" className="w-full max-h-80 object-cover" />}
                    </div>
                  )}
                  <div className="flex items-center justify-between mt-4">
                    <label className="text-primary hover:opacity-70 transition-colors p-2 hover:bg-primary/10 rounded-full cursor-pointer">
                      <ImageIcon size={22} />
                      <input type="file" accept="image/*,video/*" className="hidden" onChange={handleMediaUpload} />
                    </label>
                    <button type="submit" disabled={postMutation.isPending || (!content.trim() && !media)} className="btn btn-primary btn-sm rounded-full font-bold shadow-lg h-10 px-6">
                      {postMutation.isPending ? "Posting..." : "Post"}
                    </button>
                  </div>
                </div>
              </div>
            </form>

            {/* Posts Feed */}
            {isPostsLoading ? (
              <div className="flex justify-center py-10"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div></div>
            ) : posts.length === 0 ? (
              <div className="text-center py-20 bg-base-content/5 rounded-2xl border border-base-content/10">
                <Sparkles className="mx-auto w-12 h-12 text-base-content/20 mb-3" />
                <p className="text-base-content/60 font-medium">It's quiet here. Be the first to post!</p>
              </div>
            ) : (
              <div className="flex flex-col gap-6">
                 <PostsFeed posts={localPosts} setPosts={setLocalPosts} />
              </div>
            )}
          </>
        ) : (
          <div className="text-center py-24 bg-base-content/5 rounded-3xl border border-base-content/10 shadow-2xl mx-2">
            <Lock className="w-20 h-20 text-base-content/10 mx-auto mb-6" />
            <h3 className="text-2xl font-bold text-base-content mb-3">Private Community</h3>
            <p className="text-base-content/60 max-w-sm mx-auto mb-8 text-lg">You must join this community to see member posts and discussions.</p>
            <button onClick={() => joinMutation.mutate(community._id)} disabled={joinMutation.isPending} className="btn bg-base-content text-base-100 hover:opacity-90 px-8 py-3 rounded-full font-bold text-lg shadow-xl shadow-base-content/10 transition-transform active:scale-95 h-auto">
              Request to Join
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { Users, Plus, Image as ImageIcon, Search } from "lucide-react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { getCommunities, createCommunity, toggleJoinCommunity } from "../lib/api";
import toast from "react-hot-toast";
import useAuthUser from "../hooks/useAuthUser";

export default function CommunityPage() {
  const { authUser } = useAuthUser();
  const queryClient = useQueryClient();
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [activeTab, setActiveTab] = useState("discover"); // discover or my_communities

  const [formData, setFormData] = useState({
    name: "",
    description: "",
    isPrivate: false,
    icon: null,
    banner: null,
  });

  const { data: communitiesResponse, isLoading } = useQuery({
    queryKey: ["communities"],
    queryFn: getCommunities,
  });

  const communities = communitiesResponse?.communities || [];

  const createMutation = useMutation({
    mutationFn: createCommunity,
    onSuccess: () => {
      toast.success("Community created successfully!");
      setShowCreateModal(false);
      setFormData({ name: "", description: "", isPrivate: false, icon: null, banner: null });
      queryClient.invalidateQueries({ queryKey: ["communities"] });
    },
    onError: (error) => {
      toast.error(error.response?.data?.message || "Failed to create community");
    },
  });

  const joinMutation = useMutation({
    mutationFn: toggleJoinCommunity,
    onSuccess: (data) => {
      toast.success(data.message);
      queryClient.invalidateQueries({ queryKey: ["communities"] });
    },
    onError: () => toast.error("Action failed"),
  });

  const handleImageChange = (e, type) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        setFormData((prev) => ({ ...prev, [type]: reader.result }));
      };
    }
  };

  const handleCreateSubmit = (e) => {
    e.preventDefault();
    if (!formData.name) return toast.error("Name is required");
    createMutation.mutate(formData);
  };

  const myCommunities = communities.filter(c => c.members.includes(authUser?._id));
  const displayedCommunities = activeTab === "discover" ? communities : myCommunities;

  return (
    <div className="max-w-4xl mx-auto w-full pb-20 pt-4 px-4 font-outfit">
      
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-3xl font-extrabold text-base-content">Communities</h1>
          <p className="text-base-content/60 text-sm mt-1">Connect with like-minded people.</p>
        </div>
        <button
          onClick={() => setShowCreateModal(true)}
          className="bg-primary hover:opacity-90 text-primary-content p-2 sm:px-4 sm:py-2 rounded-xl flex items-center gap-2 transition-colors font-medium text-sm sm:text-base"
        >
          <Plus size={20} />
          <span className="hidden sm:inline">Create Community</span>
        </button>
      </div>

      <div className="flex gap-4 mb-6 border-b border-base-content/10 pb-2 overflow-x-auto no-scrollbar">
        <button
          onClick={() => setActiveTab("discover")}
          className={`font-medium px-4 py-2 rounded-full whitespace-nowrap transition-colors ${activeTab === "discover" ? "bg-primary text-primary-content" : "text-base-content hover:bg-base-content/10"}`}
        >
          Discover
        </button>
        <button
          onClick={() => setActiveTab("my_communities")}
          className={`font-medium px-4 py-2 rounded-full whitespace-nowrap transition-colors ${activeTab === "my_communities" ? "bg-primary text-primary-content" : "text-base-content hover:bg-base-content/10"}`}
        >
          My Communities
        </button>
      </div>

      {isLoading ? (
        <div className="flex items-center justify-center py-20">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
        </div>
      ) : displayedCommunities.length === 0 ? (
        <div className="text-center py-20 bg-base-content/5 rounded-2xl border border-base-content/10">
          <Users className="w-16 h-16 text-base-content/20 mx-auto mb-4" />
          <h3 className="text-xl font-bold text-base-content mb-2">No communities found</h3>
          <p className="text-base-content/60 mb-6">
            {activeTab === "discover" ? "There are no communities yet. Be the first to create one!" : "You haven't joined any communities yet."}
          </p>
          {activeTab === "my_communities" && (
            <button onClick={() => setActiveTab("discover")} className="text-blue-400 font-medium hover:underline">
               Explore Communities
            </button>
          )}
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {displayedCommunities.map((c) => {
            const isMember = c.members.includes(authUser?._id);
            return (
              <div key={c._id} className="bg-base-content/5 border border-base-content/10 rounded-2xl overflow-hidden hover:bg-base-content/10 transition-colors flex flex-col group">
                <div className="h-24 bg-gradient-to-r from-primary/30 to-secondary/30 relative">
                  {c.banner && <img src={c.banner} alt="banner" className="w-full h-full object-cover" />}
                  <div className="absolute -bottom-6 left-4 w-12 h-12 rounded-xl bg-base-300 border-2 border-base-100 overflow-hidden flex items-center justify-center">
                    {c.icon ? <img src={c.icon} alt="icon" className="w-full h-full object-cover" /> : <Users className="text-base-content/50 w-6 h-6" />}
                  </div>
                </div>
                
                <div className="pt-8 px-4 pb-4 flex flex-col flex-grow">
                  <Link to={`/community/${c._id}`} className="font-bold text-lg text-base-content mb-1 group-hover:text-primary transition-colors line-clamp-1">
                    {c.name}
                  </Link>
                  <p className="text-base-content/60 text-sm line-clamp-2 h-10 mb-4">{c.description || "No description provided."}</p>
                  
                  <div className="mt-auto flex items-center justify-between">
                    <span className="text-base-content/40 text-xs flex items-center gap-1 font-medium">
                      <Users size={14} /> {c.members.length} members
                    </span>
                    
                    <button
                      onClick={() => joinMutation.mutate(c._id)}
                      disabled={joinMutation.isPending}
                      className={`px-4 py-1.5 rounded-full text-xs font-bold transition-all ${
                        isMember 
                        ? "bg-base-content/10 text-base-content hover:bg-red-500/20 hover:text-red-400" 
                        : "bg-primary text-primary-content hover:opacity-90"
                      }`}
                    >
                      {isMember ? "Joined" : "Join"}
                    </button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Create Modal */}
      {showCreateModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-base-100 border border-base-content/10 rounded-2xl w-full max-w-md overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-4 border-b border-base-content/10 flex justify-between items-center bg-base-content/5">
              <h2 className="text-xl font-bold text-base-content">Create Community</h2>
              <button onClick={() => setShowCreateModal(false)} className="text-base-content/60 hover:text-base-content p-1">✕</button>
            </div>
            
            <form onSubmit={handleCreateSubmit} className="p-4 overflow-y-auto custom-scrollbar flex flex-col gap-4">
              
              <div>
                <label className="text-sm font-medium text-base-content/80 block mb-1">Community Name *</label>
                <input 
                  type="text" required
                  value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})}
                  className="w-full bg-base-content/5 border border-base-content/10 rounded-xl px-4 py-3 text-base-content outline-none focus:border-primary transition-all"
                  placeholder="e.g. Anime Lovers"
                  maxLength={50}
                />
              </div>

              <div>
                <label className="text-sm font-medium text-base-content/80 block mb-1">Description</label>
                <textarea 
                  value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})}
                  className="w-full bg-base-content/5 border border-base-content/10 rounded-xl px-4 py-3 text-base-content outline-none focus:border-primary transition-all resize-none h-24"
                  placeholder="What is this community about?"
                  maxLength={500}
                />
              </div>

              <div className="flex gap-4">
                <div className="flex-1">
                  <label className="text-sm font-medium text-base-content/80 block mb-2">Community Icon</label>
                  <label className="w-full h-24 bg-base-content/5 border border-base-content/10 border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer hover:bg-base-content/10 transition-colors overflow-hidden">
                    {formData.icon ? (
                      <img src={formData.icon} alt="Icon preview" className="w-full h-full object-cover" />
                    ) : (
                      <>
                        <ImageIcon className="text-base-content/40 mb-1" size={24} />
                        <span className="text-xs text-base-content/40">Upload Icon</span>
                      </>
                    )}
                    <input type="file" accept="image/*" className="hidden" onChange={(e) => handleImageChange(e, 'icon')} />
                  </label>
                </div>
                <div className="flex-1">
                  <label className="text-sm font-medium text-base-content/80 block mb-2">Banner Image</label>
                  <label className="w-full h-24 bg-base-content/5 border border-base-content/10 border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer hover:bg-base-content/10 transition-colors overflow-hidden">
                    {formData.banner ? (
                      <img src={formData.banner} alt="Banner preview" className="w-full h-full object-cover" />
                    ) : (
                      <>
                        <ImageIcon className="text-base-content/40 mb-1" size={24} />
                        <span className="text-xs text-base-content/40">Upload Banner</span>
                      </>
                    )}
                    <input type="file" accept="image/*" className="hidden" onChange={(e) => handleImageChange(e, 'banner')} />
                  </label>
                </div>
              </div>

              <div className="flex items-center gap-3 mt-2 bg-base-content/5 p-3 rounded-xl border border-base-content/5">
                <input 
                  type="checkbox" id="isPrivate"
                  checked={formData.isPrivate} onChange={e => setFormData({...formData, isPrivate: e.target.checked})}
                  className="checkbox checkbox-primary checkbox-sm"
                />
                <label htmlFor="isPrivate" className="text-sm text-base-content/90 cursor-pointer flex-1">
                  <div className="font-semibold">Private Community</div>
                  <div className="text-base-content/50 text-xs">Only members can view posts.</div>
                </label>
              </div>

              <button 
                type="submit" disabled={createMutation.isPending}
                className="w-full btn btn-primary font-bold py-3.5 rounded-xl transition-all disabled:opacity-50 mt-2 h-auto"
              >
                {createMutation.isPending ? "Creating..." : "Create Community"}
              </button>

            </form>
          </div>
        </div>
      )}

    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import { useParams, Link, useNavigate } from "react-router-dom";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { getGameSession, submitGameAnswers, startGame } from "../lib/api";
import useAuthUser from "../hooks/useAuthUser";
import { Loader2, ArrowLeft, Send, CheckCircle2, Trophy, Users, Heart, Gamepad2, Sparkles, Zap, Flame } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import toast from "react-hot-toast";
import LoveDestinyGame from "./LoveDestinyGame";
import LudoGame from "./LudoGame";
import TicTacToeGame from "./TicTacToeGame";

const CompatibilityQuiz = () => {
    const { sessionId } = useParams();
    const navigate = useNavigate();
    const queryClient = useQueryClient();
    const [answers, setAnswers] = useState([]);
    const [selectedOption, setSelectedOption] = useState(null);
    const { authUser } = useAuthUser();

    const { data: session, isLoading, isError } = useQuery({
        queryKey: ["gameSession", sessionId],
        queryFn: () => getGameSession(sessionId),
        refetchInterval: (data) => data?.status === "completed" ? false : 3000,
    });

    const { mutate: handleSubmit, isPending: isSubmitting } = useMutation({
        mutationFn: (answersToSubmit) => submitGameAnswers(sessionId, answersToSubmit),
        onSuccess: () => {
            toast.success("Sync complete!");
            queryClient.invalidateQueries({ queryKey: ["gameSession", sessionId] });
        },
        onError: (err) => toast.error(err.response?.data?.message || "Failed to submit answers"),
    });

    const { mutate: handleStartNew, isPending: isStartingNew } = useMutation({
        mutationFn: () => startGame(session.gameType),
        onSuccess: (data) => {
            navigate(`/game/${data.session._id}`);
            queryClient.invalidateQueries({ queryKey: ["gameSession", data.session._id] });
        },
        onError: (err) => toast.error(err.response?.data?.message || "Failed to start new game"),
    });

    const handleAnswer = useCallback((newAnswer) => {
        const updatedAnswers = [...answers, newAnswer];
        setAnswers(updatedAnswers);
        if (session && updatedAnswers.length === session.questions.length) {
            handleSubmit(updatedAnswers);
        }
    }, [answers, session, handleSubmit]);

    if (isLoading) {
        return (
            <div className="min-h-screen bg-[#060606] flex items-center justify-center">
                <div className="relative">
                    <Loader2 className="size-12 animate-spin text-primary" />
                    <div className="absolute inset-0 blur-2xl opacity-20 bg-primary rounded-full animate-pulse" />
                </div>
            </div>
        );
    }

    if (isError || !session) {
        return (
            <div className="min-h-screen bg-[#060606] flex flex-col items-center justify-center p-8 text-center">
                <Gamepad2 className="size-16 text-white/20 mb-4" />
                <p className="text-white/60 font-bold mb-6 italic">This game session has expired or is invalid.</p>
                <Link to="/games" className="btn btn-primary rounded-2xl h-14 btn-wide uppercase tracking-widest font-black">
                    Return to Arena
                </Link>
            </div>
        );
    }

    if (session?.gameType === "heart_destiny") return <LoveDestinyGame session={session} onAnswer={handleAnswer} />;
    if (session?.gameType === "ludo") return <LudoGame session={session} />;
    if (session?.gameType === "tic_tac_toe") return <TicTacToeGame session={session} />;

    const myId = authUser?._id?.toString();
    const hasAnswered = session.answers && myId && session.answers[myId];
    const partner = session.participants?.find(p => p._id?.toString() !== myId);
    const isCompleted = session.status === "completed";

    // COMPLETED RESULTS VIEW
    if (isCompleted) {
        return (
            <div className="min-h-screen bg-[#060606] text-white flex flex-col items-center justify-center p-8 relative overflow-hidden">
                <div className="absolute inset-x-0 top-0 h-64 bg-gradient-to-b from-primary/10 to-transparent pointer-events-none" />

                <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="text-center z-10 space-y-8 w-full max-w-md">
                    <div className="relative inline-block">
                        <Trophy className="size-32 text-yellow-400 drop-shadow-[0_0_40px_rgba(250,204,21,0.6)]" />
                        <Sparkles className="absolute -top-4 -right-4 size-10 text-primary animate-bounce" />
                    </div>

                    <div className="space-y-2">
                        <h1 className="text-5xl font-black italic tracking-tighter uppercase text-white shadow-sm">Sync Status</h1>
                        <div className="text-8xl font-black text-transparent bg-clip-text bg-gradient-to-r from-primary to-pink-500 drop-shadow-2xl">
                            {session.score}%
                        </div>
                        <p className="text-white/40 font-black uppercase tracking-[0.3em] text-[10px]">Soulmate Compatibility Score</p>
                    </div>

                    <div className="grid grid-cols-2 gap-4 bg-white/5 p-6 rounded-[40px] border border-white/10 backdrop-blur-xl">
                        <div className="text-center space-y-2">
                            <img src={authUser?.profilePic} className="size-16 rounded-[22px] mx-auto border-2 border-primary object-cover" />
                            <p className="text-[10px] font-black uppercase opacity-60">You</p>
                        </div>
                        <div className="text-center space-y-2">
                            <img src={partner?.profilePic} className="size-16 rounded-[22px] mx-auto border-2 border-pink-500 object-cover" />
                            <p className="text-[10px] font-black uppercase opacity-60">{partner?.fullName?.split(" ")[0]}</p>
                        </div>
                    </div>

                    <div className="flex flex-col gap-4">
                        <button onClick={() => handleStartNew()} disabled={isStartingNew} className="btn btn-primary h-16 rounded-3xl font-black uppercase tracking-widest text-sm shadow-glow">
                            {isStartingNew ? <Loader2 className="animate-spin size-5" /> : "Rethink Your Bond"}
                        </button>
                        <Link to="/games" className="text-xs font-black uppercase tracking-widest text-white/30 hover:text-white transition-colors">
                            Leave Arena
                        </Link>
                    </div>
                </motion.div>
                <style dangerouslySetInnerHTML={{ __html: `.shadow-glow { box-shadow: 0 0 30px -5px currentColor; }` }} />
            </div>
        );
    }

    // WAITING VIEW
    if (hasAnswered && !isCompleted) {
        return (
            <div className="min-h-screen bg-[#060606] flex flex-col items-center justify-center p-8 text-center space-y-8">
                <div className="relative">
                    <motion.div animate={{ rotate: 360 }} transition={{ duration: 10, repeat: Infinity, ease: "linear" }} className="size-48 rounded-full border-2 border-dashed border-primary/20 flex items-center justify-center">
                        <Zap className="size-12 text-primary animate-pulse" />
                    </motion.div>
                    <div className="absolute inset-0 flex items-center justify-center">
                        <Heart className="size-8 text-pink-500 fill-pink-500 animate-ping opacity-20" />
                    </div>
                </div>
                <div className="space-y-4">
                    <h2 className="text-3xl font-black italic uppercase tracking-tighter">Awaiting Sync</h2>
                    <p className="text-white/40 font-bold text-xs uppercase tracking-widest max-w-[250px]">Waiting for {partner?.fullName?.split(" ")[0]} to finish their answers...</p>
                </div>
                <div className="p-4 bg-white/5 rounded-3xl border border-white/10 animate-pulse inline-flex items-center gap-3">
                    <div className="size-10 rounded-full border-2 border-primary overflow-hidden">
                        <img src={partner?.profilePic} className="size-full object-cover" />
                    </div>
                    <span className="text-[10px] font-black uppercase tracking-widest opacity-80 italic">Analyzing connection...</span>
                </div>
            </div>
        );
    }

    // QUIZ IN PROGRESS
    const currentIdx = answers.length;
    const currentQuestion = session.questions[currentIdx];
    const progress = ((currentIdx + 1) / session.questions.length) * 100;

    return (
        <div className="min-h-screen bg-[#080808] text-white p-6 relative overflow-hidden font-outfit">
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_0%,rgba(139,92,246,0.1),transparent_70%)]" />

            <div className="relative z-10 max-w-lg mx-auto flex flex-col min-h-[90vh]">
                <header className="flex items-center justify-between mb-12">
                    <Link to="/games" className="p-3 bg-white/5 rounded-2xl border border-white/10">
                        <ArrowLeft className="size-5" />
                    </Link>
                    <div className="text-center">
                        <h1 className="text-[10px] font-black uppercase tracking-[0.5em] text-primary italic">Soul Sync</h1>
                        <p className="text-[10px] font-bold opacity-30">LEVEL {currentIdx + 1} / {session.questions.length}</p>
                    </div>
                    <div className="size-11" />
                </header>

                {/* Progress Bar */}
                <div className="w-full h-1 bg-white/5 rounded-full mb-16 overflow-hidden">
                    <motion.div initial={{ width: 0 }} animate={{ width: `${progress}%` }} className="h-full bg-gradient-to-r from-primary to-pink-500 shadow-[0_0_15px_rgba(139,92,246,0.5)]" />
                </div>

                <AnimatePresence mode="wait">
                    <motion.div key={currentIdx} initial={{ opacity: 0, x: 50 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -50 }} className="flex-1 flex flex-col justify-center">
                        <div className="space-y-8 mb-12">
                            <div className="flex items-center gap-3 opacity-40">
                                <Flame className="size-4 text-orange-400" />
                                <span className="text-[10px] font-black uppercase tracking-widest">Question {currentIdx + 1}</span>
                            </div>
                            <h2 className="text-4xl font-black italic tracking-tighter leading-tight uppercase">{currentQuestion?.text}</h2>
                        </div>

                        <div className="grid grid-cols-1 gap-4">
                            {currentQuestion?.options?.map((option, i) => (
                                <motion.button
                                    key={i}
                                    whileHover={{ scale: 1.02 }}
                                    whileTap={{ scale: 0.98 }}
                                    onClick={() => handleAnswer({ questionIndex: currentIdx, answer: option })}
                                    className="group relative p-6 text-left rounded-[32px] border-2 border-white/5 bg-white/[0.03] hover:bg-white/[0.08] hover:border-primary/50 transition-all duration-300"
                                >
                                    <div className="flex items-center justify-between">
